export const CATEGORIES = {
  INCOME: ['Salário', 'Freelance', 'Investimento', 'Presente', 'Outro'],
  EXPENSE: ['Moradia', 'Alimentação', 'Transporte', 'Utilidades', 'Lazer', 'Saúde', 'Educação', 'Compras', 'Outro']
