import React, { useState, useEffect, useMemo } from 'react';
import { Transaction, TransactionType } from './types';
import Dashboard from './components/Dashboard';
import TransactionList from './components/TransactionList';
import GeminiInsights from './components/GeminiInsights';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'transactions'>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('ff_transactions');
    return saved ? JSON.parse(saved) : [];
  });

  const [selectedMonth, setSelectedMonth] = useState(new Date().getMonth());
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());

  useEffect(() => {
    localStorage.setItem('ff_transactions', JSON.stringify(transactions));
  }, [transactions]);

  const monthNames = [
    "Janeiro", "Fevereiro", "Março", "Abril", "Maio", "Junho",
    "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"
  ];

  // Logic to determine which years are available (those with transactions + current year)
  const availableYears = useMemo(() => {
    const years = new Set<number>();
    years.add(new Date().getFullYear());
    transactions.forEach(t => {
      years.add(new Date(t.date).getFullYear());
    });
    return Array.from(years).sort((a, b) => b - a);
  }, [transactions]);

  // Logic to determine which months are available for the SELECTED year
  const availableMonths = useMemo(() => {
    const months = new Set<number>();
    // Always allow current month if the selected year is the current year
    if (selectedYear === new Date().getFullYear()) {
      months.add(new Date().getMonth());
    }

    transactions.forEach(t => {
      const d = new Date(t.date);
      if (d.getFullYear() === selectedYear) {
        months.add(d.getMonth());
      }
    });

    // If for some reason the selected month is no longer in the list (e.g. after a deletion),
    // we should still keep it visible or reset it.
    months.add(selectedMonth);

    return Array.from(months).sort((a, b) => a - b);
  }, [transactions, selectedYear, selectedMonth]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const d = new Date(t.date);
      return d.getMonth() === selectedMonth && d.getFullYear() === selectedYear;
    });
  }, [transactions, selectedMonth, selectedYear]);

  const addTransaction = (t: Omit<Transaction, 'id'>) => {
    const newTransaction = { ...t, id: crypto.randomUUID() };
    setTransactions(prev => [...prev, newTransaction]);
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      {/* Sidebar */}
      <aside className="w-full md:w-64 bg-indigo-900 text-white flex flex-col">
        <div className="p-6">
          <h1 className="text-2xl font-bold flex items-center gap-2">
            <span className="text-indigo-400">Finance</span>Flow
          </h1>
          <p className="text-xs text-indigo-300 mt-1">Controle Financeiro Inteligente</p>
        </div>

        <nav className="flex-1 px-4 space-y-2">
          <button
            onClick={() => setActiveTab('dashboard')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition ${activeTab === 'dashboard' ? 'bg-indigo-700 text-white shadow-lg' : 'hover:bg-indigo-800 text-indigo-200'}`}
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6a2 2 0 012-2h2a2 2 0 012 2v12a2 2 0 01-2 2H6a2 2 0 01-2-2V6zM14 6a2 2 0 012-2h2a2 2 0 012 2v12a2 2 0 01-2 2h-2a2 2 0 01-2-2V6z"></path></svg>
            Painel
          </button>
          <button
            onClick={() => setActiveTab('transactions')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition ${activeTab === 'transactions' ? 'bg-indigo-700 text-white shadow-lg' : 'hover:bg-indigo-800 text-indigo-200'}`}
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01"></path></svg>
            Transações
          </button>
        </nav>

        <div className="p-6 mt-auto">
          <div className="bg-indigo-800 p-4 rounded-xl text-center">
             <GeminiInsights transactions={filteredTransactions} currentMonth={monthNames[selectedMonth]} />
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 bg-slate-50 p-4 md:p-8 overflow-y-auto">
        <header className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
          <div className="flex items-center gap-4">
            <h2 className="text-2xl font-bold text-slate-800">
              {activeTab === 'dashboard' ? 'Visão Geral' : 'Registro de Transações'}
            </h2>
          </div>

          <div className="flex items-center gap-3">
            <div className="flex flex-col">
              <span className="text-[10px] font-bold text-indigo-600 uppercase ml-2 mb-0.5">Mês</span>
              <select 
                value={selectedMonth} 
                onChange={(e) => setSelectedMonth(parseInt(e.target.value))}
                className="bg-white text-indigo-900 text-sm font-bold px-4 py-2 rounded-xl shadow-md border-2 border-indigo-100 hover:border-indigo-300 focus:border-indigo-500 outline-none transition cursor-pointer min-w-[140px]"
              >
                {availableMonths.map((m) => (
                  <option key={m} value={m}>{monthNames[m]}</option>
                ))}
              </select>
            </div>

            <div className="flex flex-col">
              <span className="text-[10px] font-bold text-indigo-600 uppercase ml-2 mb-0.5">Ano</span>
              <select 
                value={selectedYear} 
                onChange={(e) => setSelectedYear(parseInt(e.target.value))}
                className="bg-white text-indigo-900 text-sm font-bold px-4 py-2 rounded-xl shadow-md border-2 border-indigo-100 hover:border-indigo-300 focus:border-indigo-500 outline-none transition cursor-pointer"
              >
                {availableYears.map(y => (
                  <option key={y} value={y}>{y}</option>
                ))}
              </select>
            </div>
          </div>
        </header>

        {activeTab === 'dashboard' ? (
          <Dashboard transactions={filteredTransactions} />
        ) : (
          <TransactionList 
            transactions={filteredTransactions} 
            onAdd={addTransaction} 
            onDelete={deleteTransaction} 
            defaultMonth={selectedMonth}
            defaultYear={selectedYear}
          />
        )}
      </main>
    </div>
  );
};

