            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="flex p-1 bg-slate-100 rounded-xl mb-4">
                <button 
                  type="button"
                  onClick={() => setFormData({...formData, type: 'EXPENSE', category: CATEGORIES.EXPENSE[0]})}
                  className={`flex-1 py-2 rounded-lg text-sm font-semibold transition ${formData.type === 'EXPENSE' ? 'bg-white text-rose-600 shadow-sm' : 'text-slate-500'}`}
