        <div className="flex flex-wrap gap-2">
          <button 
            onClick={onCopyPrevious}
            className="bg-slate-100 hover:bg-slate-200 text-slate-700 px-4 py-2 rounded-xl text-sm font-semibold transition flex items-center gap-2 border border-slate-200"
            title="Copiar todos os lançamentos do mês anterior"
          >
