  { id: '15', description: 'S (Praise)', amount: 25.00, date: '2025-02-24', category: 'Outro', type: 'EXPENSE', status: 'PENDING' }
];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'transactions'>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('ff_transactions');
    return saved ? JSON.parse(saved) : initialFebruaryData;
  });

  const [selectedMonth, setSelectedMonth] = useState(1); // Janeiro=0, Fevereiro=1
  const [selectedYear, setSelectedYear] = useState(2025);

  useEffect(() => {
    localStorage.setItem('ff_transactions', JSON.stringify(transactions));
  }, [transactions]);

  const monthNames = [
    "Janeiro", "Fevereiro", "Março", "Abril", "Maio", "Junho",
    "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"
  ];

  const availableYears = useMemo(() => {
    const years = new Set<number>();
    years.add(2025);
    years.add(new Date().getFullYear());
    transactions.forEach(t => {
      years.add(new Date(t.date).getFullYear());
    });
    return Array.from(years).sort((a, b) => b - a);
  }, [transactions]);

  const availableMonths = useMemo(() => {
    const months = new Set<number>();
    months.add(1); 
    if (selectedYear === new Date().getFullYear()) {
      months.add(new Date().getMonth());
    }

    transactions.forEach(t => {
      const d = new Date(t.date);
      if (d.getFullYear() === selectedYear) {
        months.add(d.getMonth());
      }
    });

    months.add(selectedMonth);
    return Array.from(months).sort((a, b) => a - b);
  }, [transactions, selectedYear, selectedMonth]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const d = new Date(t.date);
      return d.getMonth() === selectedMonth && d.getFullYear() === selectedYear;
    });
  }, [transactions, selectedMonth, selectedYear]);

  const addTransaction = (t: Omit<Transaction, 'id'>) => {
    const newTransaction = { ...t, id: crypto.randomUUID() };
    setTransactions(prev => [...prev, newTransaction]);
  };

  const updateTransaction = (updated: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updated.id ? updated : t));
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const toggleTransactionStatus = (id: string) => {
    setTransactions(prev => prev.map(t => 
      t.id === id ? { ...t, status: t.status === 'PAID' ? 'PENDING' : 'PAID' } : t
    ));
  };

  const copyFromPreviousMonth = () => {
    let prevMonth = selectedMonth - 1;
    let prevYear = selectedYear;
    if (prevMonth < 0) {
      prevMonth = 11;
      prevYear = selectedYear - 1;
    }

    const prevTransactions = transactions.filter(t => {
      const d = new Date(t.date);
      return d.getMonth() === prevMonth && d.getFullYear() === prevYear;
    });

    if (prevTransactions.length === 0) {
      alert(`Não foram encontrados lançamentos em ${monthNames[prevMonth]} de ${prevYear}.`);
      return;
    }

    const newTransactions: Transaction[] = prevTransactions.map(t => {
      const oldDate = new Date(t.date);
      const newDateObj = new Date(selectedYear, selectedMonth, oldDate.getDate());
      if (newDateObj.getMonth() !== selectedMonth) {
        newDateObj.setDate(0); 
      }

      return {
        ...t,
        id: crypto.randomUUID(),
        date: newDateObj.toISOString().split('T')[0],
        status: 'PENDING'
      };
    });

    setTransactions(prev => [...prev, ...newTransactions]);
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">
      {/* Sidebar - Mobile Responsive */}
      <aside className="w-full md:w-64 bg-indigo-900 text-white flex flex-col md:sticky md:top-0 md:h-screen z-20">
        <div className="p-4 md:p-6 flex justify-between items-center md:block">
          <div>
            <h1 className="text-xl md:text-2xl font-bold flex items-center gap-2">
              <span className="text-indigo-400">Finance</span>Flow
            </h1>
            <p className="text-[10px] md:text-xs text-indigo-300 mt-0 md:mt-1">Controle Financeiro Inteligente</p>
          </div>
          <div className="md:hidden">
            <GeminiInsights transactions={filteredTransactions} currentMonth={monthNames[selectedMonth]} mobileCompact />
          </div>
        </div>

        <nav className="flex md:flex-col px-2 md:px-4 pb-2 md:pb-0 space-x-2 md:space-x-0 md:space-y-2 overflow-x-auto md:overflow-x-visible no-scrollbar">
          <button
            onClick={() => setActiveTab('dashboard')}
            className={`flex-1 md:flex-none flex items-center justify-center md:justify-start gap-3 px-4 py-3 rounded-xl transition whitespace-nowrap ${activeTab === 'dashboard' ? 'bg-indigo-700 text-white shadow-lg' : 'hover:bg-indigo-800 text-indigo-200'}`}
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6a2 2 0 012-2h2a2 2 0 012 2v12a2 2 0 01-2 2H6a2 2 0 01-2-2V6zM14 6a2 2 0 012-2h2a2 2 0 012 2v12a2 2 0 01-2 2h-2a2 2 0 01-2-2V6z"></path></svg>
            <span className="text-sm font-semibold">Painel</span>
          </button>
          <button
            onClick={() => setActiveTab('transactions')}
            className={`flex-1 md:flex-none flex items-center justify-center md:justify-start gap-3 px-4 py-3 rounded-xl transition whitespace-nowrap ${activeTab === 'transactions' ? 'bg-indigo-700 text-white shadow-lg' : 'hover:bg-indigo-800 text-indigo-200'}`}
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01"></path></svg>
            <span className="text-sm font-semibold">Lançamentos</span>
          </button>
        </nav>

        <div className="hidden md:block p-6 mt-auto">
          <div className="bg-indigo-800 p-4 rounded-xl text-center">
             <GeminiInsights transactions={filteredTransactions} currentMonth={monthNames[selectedMonth]} />
          </div>
        </div>
      </aside>

      <main className="flex-1 p-4 md:p-8 overflow-y-auto">
        <header className="flex flex-col md:flex-row justify-between items-center mb-6 md:mb-8 gap-4">
          <h2 className="text-xl md:text-2xl font-bold text-slate-800 self-start md:self-center">
            {activeTab === 'dashboard' ? 'Visão Geral' : 'Transações'}
          </h2>

          <div className="flex items-center gap-2 md:gap-3 w-full md:w-auto">
            <div className="flex-1 md:flex-none flex flex-col">
              <span className="text-[10px] font-bold text-indigo-600 uppercase ml-2 mb-0.5">Mês</span>
              <select 
                value={selectedMonth} 
                onChange={(e) => setSelectedMonth(parseInt(e.target.value))}
                className="w-full bg-white text-indigo-900 text-xs md:text-sm font-bold px-3 md:px-4 py-2 rounded-xl shadow-sm border border-slate-200 focus:border-indigo-500 outline-none transition cursor-pointer min-w-[110px] md:min-w-[140px]"
              >
                {availableMonths.map((m) => (
                  <option key={m} value={m}>{monthNames[m]}</option>
                ))}
              </select>
            </div>

            <div className="flex-none flex flex-col">
              <span className="text-[10px] font-bold text-indigo-600 uppercase ml-2 mb-0.5">Ano</span>
              <select 
                value={selectedYear} 
                onChange={(e) => setSelectedYear(parseInt(e.target.value))}
                className="bg-white text-indigo-900 text-xs md:text-sm font-bold px-3 md:px-4 py-2 rounded-xl shadow-sm border border-slate-200 focus:border-indigo-500 outline-none transition cursor-pointer"
              >
                {availableYears.map(y => (
                  <option key={y} value={y}>{y}</option>
                ))}
              </select>
            </div>
          </div>
        </header>

        {activeTab === 'dashboard' ? (
          <Dashboard transactions={filteredTransactions} />
        ) : (
          <TransactionList 
            transactions={filteredTransactions} 
            onAdd={addTransaction} 
            onUpdate={updateTransaction}
            onDelete={deleteTransaction}
            onToggleStatus={toggleTransactionStatus}
            onCopyPrevious={copyFromPreviousMonth}
            defaultMonth={selectedMonth}
            defaultYear={selectedYear}
          />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Transaction, TransactionType, TransactionStatus, CATEGORIES } from '../types';

interface Props {
  transactions: Transaction[];
  onAdd: (t: Omit<Transaction, 'id'>) => void;
  onUpdate: (t: Transaction) => void;
  onDelete: (id: string) => void;
  onToggleStatus: (id: string) => void;
  onCopyPrevious: () => void;
  defaultMonth: number;
  defaultYear: number;
}

const TransactionList: React.FC<Props> = ({ 
  transactions, 
  onAdd, 
  onUpdate, 
  onDelete, 
  onToggleStatus, 
  onCopyPrevious,
  defaultMonth, 
  defaultYear 
}) => {
  const [showModal, setShowModal] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [viewMode, setViewMode] = useState<'table' | 'list'>(() => {
    // No mobile, o padrão ideal é lista
    return window.innerWidth < 768 ? 'list' : 'table';
  });

  const getDefaultDate = () => {
    const now = new Date();
    const date = new Date(defaultYear, defaultMonth, now.getDate());
    if (date.getMonth() !== defaultMonth) {
       return new Date(defaultYear, defaultMonth + 1, 0).toISOString().split('T')[0];
    }
    return date.toISOString().split('T')[0];
  };

  const initialFormState = {
    description: '',
    amount: '',
    date: getDefaultDate(),
    category: 'Outro',
    type: 'EXPENSE' as TransactionType,
    status: 'PENDING' as TransactionStatus
  };

  const [formData, setFormData] = useState(initialFormState);

  useEffect(() => {
    if (!showModal) {
      setFormData({
        ...initialFormState,
        date: getDefaultDate(),
        category: formData.type === 'INCOME' ? CATEGORIES.INCOME[0] : CATEGORIES.EXPENSE[0]
      });
      setEditingTransaction(null);
    }
  }, [defaultMonth, defaultYear, showModal]);

  const handleEditClick = (t: Transaction) => {
    setEditingTransaction(t);
    setFormData({
      description: t.description,
      amount: t.amount.toString(),
      date: t.date,
      category: t.category,
      type: t.type,
      status: t.status
    });
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.description || !formData.amount) return;

    if (editingTransaction) {
      onUpdate({
        id: editingTransaction.id,
        description: formData.description,
        amount: parseFloat(formData.amount),
        date: formData.date,
        category: formData.category,
        type: formData.type,
        status: formData.status
      });
    } else {
      onAdd({
        description: formData.description,
        amount: parseFloat(formData.amount),
        date: formData.date,
        category: formData.category,
        type: formData.type,
        status: formData.status
      });
    }

    setFormData(initialFormState);
    setShowModal(false);
    setEditingTransaction(null);
  };

  const sortedTransactions = [...transactions].sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  return (
    <div className="space-y-4">
      {/* List Controls */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 bg-white p-4 rounded-2xl shadow-sm border border-slate-100">
        <div className="flex items-center gap-2 bg-slate-100 p-1 rounded-xl">
          <button 
            onClick={() => setViewMode('table')}
            className={`p-2 rounded-lg transition-all ${viewMode === 'table' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            title="Visualização em Tabela"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 10h18M3 14h18m-9-4v8m-7 0h14a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z"></path></svg>
          </button>
          <button 
            onClick={() => setViewMode('list')}
            className={`p-2 rounded-lg transition-all ${viewMode === 'list' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            title="Visualização em Lista"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 10h16M4 14h16M4 18h16"></path></svg>
          </button>
        </div>

        <div className="flex gap-2 w-full sm:w-auto">
          <button 
            onClick={onCopyPrevious}
            className="flex-1 sm:flex-none bg-slate-100 hover:bg-slate-200 text-slate-700 px-3 py-2 rounded-xl text-xs md:text-sm font-semibold transition border border-slate-200 flex items-center justify-center gap-2"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 7v8a2 2 0 002 2h6M8 7a2 2 0 012-2h6a2 2 0 012 2v8a2 2 0 01-2 2H10a2 2 0 01-2-2z"></path></svg>
            <span className="hidden sm:inline">Importar Mês</span>
            <span className="sm:hidden">Importar</span>
          </button>
          <button 
            onClick={() => {
              setEditingTransaction(null);
              setFormData(initialFormState);
              setShowModal(true);
            }}
            className="flex-1 sm:flex-none bg-indigo-600 hover:bg-indigo-700 text-white px-3 py-2 rounded-xl text-xs md:text-sm font-semibold transition flex items-center justify-center gap-2 shadow-md"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6v6m0 0v6m0-6h6m-6 0H6"></path></svg>
            Adicionar
          </button>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        {viewMode === 'table' ? (
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-slate-50 text-slate-500 text-[10px] md:text-xs uppercase font-bold tracking-wider">
                <tr>
                  <th className="px-4 md:px-6 py-4">Descrição</th>
                  <th className="px-4 md:px-6 py-4 hidden md:table-cell">Categoria</th>
                  <th className="px-4 md:px-6 py-4">Status</th>
                  <th className="px-4 md:px-6 py-4 hidden sm:table-cell">Data</th>
                  <th className="px-4 md:px-6 py-4 text-right">Valor</th>
                  <th className="px-4 md:px-6 py-4 w-20"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {sortedTransactions.length > 0 ? (
                  sortedTransactions.map(t => (
                    <tr key={t.id} className="hover:bg-slate-50/50 transition group">
                      <td className="px-4 md:px-6 py-4">
                        <div className="font-semibold text-slate-800 text-sm md:text-base">{t.description}</div>
                        <div className="md:hidden text-[10px] text-slate-400 mt-0.5">{t.category}</div>
                      </td>
                      <td className="px-4 md:px-6 py-4 hidden md:table-cell">
                        <span className="px-2 py-1 bg-slate-100 text-slate-600 rounded-lg text-[10px] font-bold">
                          {t.category}
                        </span>
                      </td>
                      <td className="px-4 md:px-6 py-4">
                        <button 
                          onClick={() => onToggleStatus(t.id)}
                          className={`px-2 md:px-3 py-1 rounded-full text-[9px] md:text-[10px] font-bold uppercase transition-all whitespace-nowrap ${
                            t.status === 'PAID' 
                              ? 'bg-emerald-100 text-emerald-700' 
                              : 'bg-amber-100 text-amber-700'
                          }`}
                        >
                          {t.status === 'PAID' ? (t.type === 'INCOME' ? 'Recebido' : 'Pago') : 'Pendente'}
                        </button>
                      </td>
                      <td className="px-4 md:px-6 py-4 hidden sm:table-cell text-xs text-slate-500">
                        {new Date(t.date).toLocaleDateString('pt-BR')}
                      </td>
                      <td className={`px-4 md:px-6 py-4 text-right font-bold text-sm md:text-base ${t.type === 'INCOME' ? 'text-emerald-600' : 'text-rose-600'}`}>
                        {t.type === 'INCOME' ? '+' : '-'} R$ {t.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                      </td>
                      <td className="px-4 md:px-6 py-4 text-right">
                        <div className="flex items-center justify-end gap-1 md:gap-3">
                          <button onClick={() => handleEditClick(t)} className="p-1 text-slate-400 hover:text-indigo-600 transition">
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z"></path></svg>
                          </button>
                          <button onClick={() => onDelete(t.id)} className="p-1 text-slate-400 hover:text-rose-600 transition">
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td colSpan={6} className="px-6 py-12 text-center text-slate-400 text-sm">Nenhum lançamento encontrado.</td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="divide-y divide-slate-100">
            {sortedTransactions.length > 0 ? (
              sortedTransactions.map(t => (
                <div key={t.id} className="p-4 hover:bg-slate-50 transition active:bg-slate-100 flex flex-col gap-3">
                  <div className="flex justify-between items-start">
                    <div className="flex-1 pr-4">
                      <div className="text-sm font-bold text-slate-800 line-clamp-1">{t.description}</div>
                      <div className="flex items-center gap-2 mt-1">
                        <span className="text-[10px] text-slate-400">{new Date(t.date).toLocaleDateString('pt-BR')}</span>
                        <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
                        <span className="text-[10px] font-medium text-indigo-600">{t.category}</span>
                      </div>
                    </div>
                    <div className={`text-sm font-extrabold whitespace-nowrap ${t.type === 'INCOME' ? 'text-emerald-600' : 'text-rose-600'}`}>
                      {t.type === 'INCOME' ? '+' : '-'} R$ {t.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                    </div>
                  </div>
                  <div className="flex items-center justify-between mt-1">
                    <button 
                      onClick={() => onToggleStatus(t.id)}
                      className={`px-3 py-1 rounded-full text-[9px] font-bold uppercase transition-all ${
                        t.status === 'PAID' 
                          ? 'bg-emerald-100 text-emerald-700' 
                          : 'bg-amber-100 text-amber-700'
                      }`}
                    >
                      {t.status === 'PAID' ? (t.type === 'INCOME' ? 'Recebido' : 'Pago') : 'Pendente'}
                    </button>
                    <div className="flex gap-4">
                      <button onClick={() => handleEditClick(t)} className="flex items-center gap-1 text-[11px] font-bold text-slate-400 hover:text-indigo-600">
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z"></path></svg>
                        Editar
                      </button>
                      <button onClick={() => onDelete(t.id)} className="flex items-center gap-1 text-[11px] font-bold text-slate-400 hover:text-rose-600">
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                        Excluir
                      </button>
                    </div>
                  </div>
                </div>
              ))
            ) : (
              <div className="p-12 text-center text-slate-400 text-sm italic">Nenhum lançamento.</div>
            )}
          </div>
        )}
      </div>

      {showModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-end sm:items-center justify-center z-[100] p-0 sm:p-4">
          <div className="bg-white rounded-t-3xl sm:rounded-3xl w-full max-w-md p-6 md:p-8 shadow-2xl animate-in slide-in-from-bottom sm:zoom-in-95 duration-200 overflow-y-auto max-h-[90vh]">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-slate-800">
                {editingTransaction ? 'Editar' : 'Novo'} Lançamento
              </h3>
              <div className="flex gap-2">
                <button 
                  type="button"
                  onClick={() => setFormData({...formData, status: 'PAID'})}
                  className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase transition ${formData.status === 'PAID' ? 'bg-indigo-600 text-white shadow-md' : 'bg-slate-100 text-slate-400'}`}
                >
                  Confirmado
                </button>
                <button 
                  type="button"
                  onClick={() => setFormData({...formData, status: 'PENDING'})}
                  className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase transition ${formData.status === 'PENDING' ? 'bg-amber-500 text-white shadow-md' : 'bg-slate-100 text-slate-400'}`}
                >
                  Pendente
                </button>
              </div>
            </div>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="flex p-1 bg-slate-100 rounded-xl mb-4">
                <button 
                  type="button"
                  onClick={() => setFormData({...formData, type: 'EXPENSE', category: CATEGORIES.EXPENSE[0]})}
                  className={`flex-1 py-2 rounded-lg text-sm font-bold transition ${formData.type === 'EXPENSE' ? 'bg-white text-rose-600 shadow-sm' : 'text-slate-500'}`}
                >
                  Despesa
                </button>
                <button 
                  type="button"
                  onClick={() => setFormData({...formData, type: 'INCOME', category: CATEGORIES.INCOME[0]})}
                  className={`flex-1 py-2 rounded-lg text-sm font-bold transition ${formData.type === 'INCOME' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-500'}`}
                >
                  Receita
                </button>
              </div>

              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Descrição</label>
                <input 
                  type="text" 
                  value={formData.description}
                  onChange={(e) => setFormData({...formData, description: e.target.value})}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:border-indigo-500 focus:ring-4 focus:ring-indigo-50 outline-none transition bg-white text-slate-900 font-medium"
                  placeholder="Ex: Aluguel, Salário..."
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Valor (R$)</label>
                  <input 
                    type="number" 
                    step="0.01"
                    value={formData.amount}
                    onChange={(e) => setFormData({...formData, amount: e.target.value})}
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:border-indigo-500 focus:ring-4 focus:ring-indigo-50 outline-none transition bg-white text-slate-900 font-bold"
                    placeholder="0,00"
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Data</label>
                  <input 
                    type="date" 
                    value={formData.date}
                    onChange={(e) => setFormData({...formData, date: e.target.value})}
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:border-indigo-500 focus:ring-4 focus:ring-indigo-50 outline-none transition bg-white text-slate-900 font-medium"
                  />
                </div>
              </div>

              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Categoria</label>
                <select 
                  value={formData.category}
                  onChange={(e) => setFormData({...formData, category: e.target.value})}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:border-indigo-500 focus:ring-4 focus:ring-indigo-50 outline-none transition bg-white text-slate-900 font-medium"
                >
                  {formData.type === 'INCOME' 
                    ? CATEGORIES.INCOME.map(c => <option key={c} value={c}>{c}</option>)
                    : CATEGORIES.EXPENSE.map(c => <option key={c} value={c}>{c}</option>)
                  }
                </select>
              </div>

              <div className="flex flex-col sm:flex-row gap-3 pt-6">
                <button 
                  type="button" 
                  onClick={() => { setShowModal(false); setEditingTransaction(null); }}
                  className="order-2 sm:order-1 flex-1 px-4 py-3 rounded-xl border border-slate-200 text-slate-600 font-bold hover:bg-slate-50 transition"
                >
                  Cancelar
                </button>
                <button 
                  type="submit" 
                  className={`order-1 sm:order-2 flex-1 px-4 py-3 rounded-xl text-white font-bold transition shadow-xl ${formData.type === 'INCOME' ? 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-100' : 'bg-rose-600 hover:bg-rose-700 shadow-rose-100'}`}
                >
                  {editingTransaction ? 'Atualizar' : 'Salvar'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default TransactionList;

import React, { useState } from 'react';
import { getFinancialInsights } from '../services/geminiService';
import { Transaction, FinancialInsight } from '../types';

interface Props {
  transactions: Transaction[];
  currentMonth: string;
  mobileCompact?: boolean;
}

const GeminiInsights: React.FC<Props> = ({ transactions, currentMonth, mobileCompact = false }) => {
  const [loading, setLoading] = useState(false);
  const [insight, setInsight] = useState<FinancialInsight | null>(null);
  const [showPopup, setShowPopup] = useState(false);

  const fetchInsights = async () => {
    if (transactions.length === 0) return;
    setLoading(true);
    try {
      const result = await getFinancialInsights(transactions, currentMonth);
      setInsight(result);
      setShowPopup(true);
    } catch (err) {
      alert("Erro ao buscar insights da IA. Tente novamente.");
    } finally {
      setLoading(false);
    }
  };

  if (mobileCompact) {
    return (
      <button
        onClick={fetchInsights}
        disabled={loading || transactions.length === 0}
        className={`p-2 rounded-xl transition-all ${loading ? 'bg-indigo-700/50' : 'bg-indigo-700 hover:bg-indigo-600 active:scale-95 shadow-lg'}`}
        title="IA Insights"
      >
        {loading ? (
          <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
        ) : (
          <svg className="w-5 h-5 text-indigo-100" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"></path></svg>
        )}
      </button>
    );
  }

  return (
    <>
      <button
        onClick={fetchInsights}
        disabled={loading || transactions.length === 0}
        className={`w-full flex items-center justify-center gap-2 py-2 rounded-lg text-sm font-bold transition-all ${loading ? 'bg-indigo-700 opacity-50' : 'bg-white text-indigo-900 hover:scale-105 active:scale-95 shadow-md'}`}
      >
        {loading ? (
          <div className="w-4 h-4 border-2 border-indigo-900 border-t-transparent rounded-full animate-spin"></div>
        ) : (
          <svg className="w-5 h-5 text-indigo-500" fill="currentColor" viewBox="0 0 20 20"><path d="M11 3a1 1 0 10-2 0v1a1 1 0 102 0V3zM15.657 5.757a1 1 0 00-1.414-1.414l-.707.707a1 1 0 001.414 1.414l.707-.707zM18 10a1 1 0 01-1 1h-1a1 1 0 110-2h1a1 1 0 011 1zM5.05 6.464A1 1 0 106.464 5.05l-.707-.707a1 1 0 00-1.414 1.414l.707.707zM5 10a1 1 0 01-1 1H3a1 1 0 110-2h1a1 1 0 011 1zM8 16v-1a1 1 0 112 0v1a1 1 0 11-2 0zM13.536 14.243a1 1 0 011.414 0l.707.707a1 1 0 01-1.414 1.414l-.707-.707a1 1 0 010-1.414zM15 10a5 5 0 11-10 0 5 5 0 0110 0z"></path></svg>
        )}
        IA Insights
      </button>

      {showPopup && insight && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-end sm:items-center justify-center z-[100] p-0 sm:p-4">
          <div className="bg-white rounded-t-3xl sm:rounded-3xl w-full max-w-lg p-6 md:p-8 shadow-2xl relative overflow-hidden animate-in slide-in-from-bottom sm:zoom-in-95 duration-200">
            <div className="absolute top-0 left-0 w-full h-1.5 bg-gradient-to-r from-indigo-500 to-purple-500"></div>

            <button 
              onClick={() => setShowPopup(false)}
              className="absolute top-4 right-4 p-2 text-slate-400 hover:text-slate-600 transition active:scale-90"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
            </button>

            <div className="flex items-center gap-3 mb-6">
              <div className="p-3 bg-indigo-50 rounded-2xl text-indigo-600">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z"></path></svg>
              </div>
              <h3 className="text-xl font-extrabold text-slate-800">Insights da IA</h3>
            </div>

            <div className="space-y-6 max-h-[70vh] overflow-y-auto pr-1">
              <div className="bg-indigo-50/50 p-4 rounded-2xl border border-indigo-100 text-slate-700 leading-relaxed">
                "{insight.summary}"
              </div>

              <div>
                <h4 className="font-bold text-slate-800 mb-3 flex items-center gap-2 text-sm uppercase tracking-wider">
                  <span className="w-2 h-2 bg-indigo-500 rounded-full"></span>
                  Recomendações
                </h4>
                <ul className="space-y-3">
                  {insight.recommendations.map((rec, i) => (
                    <li key={i} className="flex gap-3 text-sm text-slate-600 bg-white p-4 rounded-2xl border border-slate-100 shadow-sm transition hover:border-indigo-200">
                      <span className="font-black text-indigo-500 shrink-0">{i + 1}.</span>
                      <span className="font-medium">{rec}</span>
                    </li>
                  ))}
                </ul>
              </div>

              <div className="flex items-center justify-between pt-6 border-t border-slate-100">
                <span className="text-sm font-bold text-slate-400 uppercase tracking-widest">Alerta</span>
                <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest ${
                  insight.alertLevel === 'low' ? 'bg-green-100 text-green-700' :
                  insight.alertLevel === 'medium' ? 'bg-yellow-100 text-yellow-700' :
                  'bg-red-100 text-red-700'
                }`}>
                  {insight.alertLevel === 'low' ? 'Saudável' : insight.alertLevel === 'medium' ? 'Atenção' : 'Crítico'}
                </span>
              </div>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

export default GeminiInsights;

