                <button type="button" onClick={() => setFormData({...formData, type: 'INCOME', category: CATEGORIES.INCOME[0]})} className={`flex-1 py-2 rounded-lg text-sm font-bold transition ${formData.type === 'INCOME' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-500'}`}>Receita</button>
