                  <input type="number" step="0.01" value={formData.amount} onChange={(e) => setFormData({...formData, amount: e.target.value})} className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:border-indigo-500 focus:ring-4 focus:ring-indigo-50 outline-none transition bg-white text-slate-900 font-bold" placeholder="0,00" />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Data</label>
                  <input type="date" value={formData.date} onChange={(e) => setFormData({...formData, date: e.target.value})} className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:border-indigo-500 outline-none bg-white text-slate-900 font-medium" />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Frequência</label>
                  <select value={formData.frequency} onChange={(e) => setFormData({...formData, frequency: e.target.value as TransactionFrequency})} className="w-full px-3 py-3 rounded-xl border border-slate-200 outline-none bg-white text-slate-800 font-semibold text-sm">
                    <option value="FIXED">Fixo</option>
                    <option value="SPORADIC">Esporádico</option>
                  </select>
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Status</label>
                  <select value={formData.status} onChange={(e) => setFormData({...formData, status: e.target.value as TransactionStatus})} className="w-full px-3 py-3 rounded-xl border border-slate-200 outline-none bg-white text-slate-800 font-semibold text-sm">
                    <option value="PENDING">Pendente</option>
                    <option value="PAID">{formData.type === 'INCOME' ? 'Recebido' : 'Pago'}</option>
                  </select>
                </div>
              </div>

              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Categoria</label>
                <select value={formData.category} onChange={(e) => setFormData({...formData, category: e.target.value})} className="w-full px-4 py-3 rounded-xl border border-slate-200 outline-none bg-white text-slate-900 font-semibold text-sm">
                  {(formData.type === 'INCOME' ? CATEGORIES.INCOME : CATEGORIES.EXPENSE).map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>

              <div className="flex flex-col sm:flex-row gap-3 pt-4">
                <button type="button" onClick={() => setShowModal(false)} className="order-2 sm:order-1 flex-1 px-4 py-3 rounded-xl border border-slate-200 text-slate-500 font-bold hover:bg-slate-50 transition">Cancelar</button>
                <button type="submit" className={`order-1 sm:order-2 flex-1 px-4 py-3 rounded-xl text-white font-bold transition shadow-xl ${formData.type === 'INCOME' ? 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-100' : 'bg-rose-600 hover:bg-rose-700 shadow-rose-100'}`}>{editingTransaction ? 'Atualizar' : 'Salvar'}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default TransactionList;

