Para integrar o **FinanceFlow AI** com o Google Sheets, você precisará de duas partes: o código do **Google Apps Script** (que rodará no Google Drive) e a atualização do serviço no seu **Frontend** para realizar as chamadas de API.

Aqui estão as especificações da atualização:

1.  **Google Apps Script**: Um script robusto que gerencia operações de leitura, criação, atualização e exclusão (CRUD) diretamente na planilha.
2.  **Frontend Service**: Criação de `services/googleSheetsService.ts` para centralizar as chamadas `fetch` para a URL do Web App do Google.
3.  **App Sync**: O `App.tsx` será atualizado para carregar os dados da nuvem ao iniciar e sincronizar as alterações automaticamente.

### Parte 1: Código do Google Apps Script

Crie uma nova planilha no Google Sheets, vá em **Extensões > Apps Script** e cole o código abaixo:

```javascript
/**
 * FINANCEFLOW AI - BACKEND SCRIPT
 * Configuração:
 * 1. Cole este código no Apps Script da sua planilha.
 * 2. Clique em 'Implantar' > 'Nova implantação'.
 * 3. Selecione 'App da Web'.
 * 4. Configurar 'Quem pode acessar' como 'Qualquer pessoa'.
 */

function doGet(e) {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();
  const data = sheet.getDataRange().getValues();
  const headers = data.shift();

  const json = data.map(row => {
    const obj = {};
    headers.forEach((header, i) => {
      obj[header] = row[i];
    });
    return obj;
  });

  return ContentService.createTextOutput(JSON.stringify(json))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();
  const contents = JSON.parse(e.postData.contents);
  const { action, payload } = contents;

  const data = sheet.getDataRange().getValues();
  const headers = data[0];

  if (action === 'save') {
    // Upsert (Update or Insert)
    const idIndex = headers.indexOf('id');
    let rowIndex = -1;

    for (let i = 1; i < data.length; i++) {
      if (data[i][idIndex] === payload.id) {
        rowIndex = i + 1;
        break;
      }
    }

    const rowData = headers.map(h => payload[h] !== undefined ? payload[h] : "");

    if (rowIndex > 0) {
      sheet.getRange(rowIndex, 1, 1, headers.length).setValues([rowData]);
    } else {
      sheet.appendRow(rowData);
    }

    return ContentService.createTextOutput(JSON.stringify({status: 'success'}))
      .setMimeType(ContentService.MimeType.JSON);
  }

  if (action === 'delete') {
    const idIndex = headers.indexOf('id');
    for (let i = 1; i < data.length; i++) {
      if (data[i][idIndex] === payload.id) {
        sheet.deleteRow(i + 1);
        break;
      }
    }
    return ContentService.createTextOutput(JSON.stringify({status: 'success'}))
      .setMimeType(ContentService.MimeType.JSON);
  }

  if (action === 'syncAll') {
    // Limpa tudo exceto cabeçalho e reinsere
    sheet.getRange(2, 1, sheet.getLastRow() > 1 ? sheet.getLastRow() - 1 : 1, headers.length).clearContent();
    if (payload.length > 0) {
      const rows = payload.map(t => headers.map(h => t[h] || ""));
      sheet.getRange(2, 1, rows.length, headers.length).setValues(rows);
    }
    return ContentService.createTextOutput(JSON.stringify({status: 'success'}))
      .setMimeType(ContentService.MimeType.JSON);
  }
}

// Configuração inicial da planilha
function setupSheet() {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();
  const headers = ['id', 'description', 'amount', 'date', 'category', 'type', 'status', 'frequency'];
  sheet.getRange(1, 1, 1, headers.length).setValues([headers]);
  sheet.setFrozenRows(1);
}
```

