// Substitua pela URL gerada ao implantar seu Apps Script como Web App
// Em um cenário real, isso viria de process.env.SHEETS_API_URL
const API_URL = "https://script.google.com/macros/s/SUA_URL_AQUI/exec";

export const sheetsService = {
  async getAll(): Promise<Transaction[]> {
    if (API_URL.includes("SUA_URL_AQUI")) return [];
    try {
      const response = await fetch(API_URL);
      if (!response.ok) throw new Error("Erro ao carregar dados do Google Sheets");
      return await response.json();
    } catch (error) {
      console.error(error);
      return [];
    }
  },

  async save(transaction: Transaction): Promise<boolean> {
    if (API_URL.includes("SUA_URL_AQUI")) return false;
    try {
      await fetch(API_URL, {
        method: "POST",
        mode: "no-cors", // Google Apps Script requer no-cors para POST simples
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ action: "save", payload: transaction })
      });
      return true;
    } catch (error) {
      console.error(error);
      return false;
    }
  },

  async delete(id: string): Promise<boolean> {
    if (API_URL.includes("SUA_URL_AQUI")) return false;
    try {
      await fetch(API_URL, {
        method: "POST",
        mode: "no-cors",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ action: "delete", payload: { id } })
      });
      return true;
    } catch (error) {
      console.error(error);
      return false;
    }
  },

  async syncAll(transactions: Transaction[]): Promise<boolean> {
    if (API_URL.includes("SUA_URL_AQUI")) return false;
    try {
      await fetch(API_URL, {
        method: "POST",
        mode: "no-cors",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ action: "syncAll", payload: transactions })
      });
      return true;
    } catch (error) {
      console.error(error);
      return false;
    }
  }
};

