import { Transaction } from "../types";

// URL do Web App do Google Apps Script
const API_URL = "https://script.google.com/macros/s/AKfycbxmv0_ALKP6upCFRm_soe1Jh6HKUsKJpbACsWdfTsJLCfn6fBmdA1xLRNmYKScBKdkQ/exec";

export const sheetsService = {
  async getAll(): Promise<Transaction[]> {
    if (!API_URL || API_URL.includes("SUA_URL_AQUI")) return [];

    try {
      // Usamos redirect: 'follow' explicitamente e garantimos que não há cabeçalhos extras
      // que possam disparar um preflight CORS desnecessário.
      const response = await fetch(API_URL, {
        method: "GET",
        mode: "cors",
        cache: "no-cache",
        redirect: "follow"
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const data = await response.json();

      if (!Array.isArray(data)) {
        console.warn("Google Sheets retornou um formato inesperado:", data);
        return [];
      }

      return data.map((t: any) => ({
        ...t,
        amount: typeof t.amount === 'string' ? parseFloat(t.amount.replace(',', '.')) : (parseFloat(t.amount) || 0)
      }));
    } catch (error) {
      // Erro "Failed to fetch" cai aqui
      console.error("Erro ao conectar com Google Sheets:", error);
      throw error; // Re-lançamos para o App.tsx lidar com o fallback
    }
  },

  async save(transaction: Transaction): Promise<boolean> {
    if (!API_URL || API_URL.includes("SUA_URL_AQUI")) return false;
    try {
      // Para POST no Apps Script, 'no-cors' é frequentemente necessário para evitar
      // erros de preflight que o Google não suporta bem em domínios de script.
      await fetch(API_URL, {
        method: "POST",
        mode: "no-cors",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ action: "save", payload: transaction })
      });
      return true;
    } catch (error) {
      console.error("Erro ao salvar no Google Sheets:", error);
      return false;
    }
  },

  async delete(id: string): Promise<boolean> {
    if (!API_URL || API_URL.includes("SUA_URL_AQUI")) return false;
    try {
      await fetch(API_URL, {
        method: "POST",
        mode: "no-cors",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ action: "delete", payload: { id } })
      });
      return true;
    } catch (error) {
      console.error("Erro ao deletar no Google Sheets:", error);
      return false;
    }
  },

  async syncAll(transactions: Transaction[]): Promise<boolean> {
    if (!API_URL || API_URL.includes("SUA_URL_AQUI")) return false;
    try {
      await fetch(API_URL, {
        method: "POST",
        mode: "no-cors",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ action: "syncAll", payload: transactions })
      });
      return true;
    } catch (error) {
      console.error("Erro ao sincronizar Google Sheets:", error);
      return false;
    }
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { Transaction, TransactionType } from './types';
import Dashboard from './components/Dashboard';
import TransactionList from './components/TransactionList';
