            className={`flex-1 md:flex-none flex items-center justify-center md:justify-start gap-3 px-4 py-3 rounded-xl transition whitespace-nowrap ${activeTab === 'dashboard' ? 'bg-indigo-700 text-white shadow-lg' : 'hover:bg-indigo-800 text-indigo-200'}`}
          >
