Para garantir que os dados adicionados no aplicativo apareçam na sua planilha do Google, precisamos de duas coisas:
1.  **O Código do Google Apps Script**: Você deve colar o código abaixo no seu editor de script do Google (Extensões > Apps Script) e **implantar como Web App** (Quem pode acessar: Qualquer pessoa).
2.  **Ajuste no App**: Configurar o envio para que o Google receba os dados corretamente sem bloqueios de CORS.

### 1. Instruções para a sua Planilha (Google Apps Script)

Copie e cole este código no seu Google Script:

```javascript
function doGet(e) {
  var sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();
  var data = sheet.getDataRange().getValues();
  var headers = data[0];
  var json = [];

  for (var i = 1; i < data.length; i++) {
    var obj = {};
    for (var j = 0; j < headers.length; j++) {
      obj[headers[j]] = data[i][j];
    }
    json.push(obj);
  }

  return ContentService.createTextOutput(JSON.stringify(json))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  var sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();
  var body = JSON.parse(e.postData.contents);
  var action = body.action;
  var payload = body.payload;

  if (action === 'save') {
    var data = sheet.getDataRange().getValues();
    var idIndex = 0; // Coluna A (ID)
    var found = false;

    for (var i = 1; i < data.length; i++) {
      if (data[i][idIndex] == payload.id) {
        sheet.getRange(i + 1, 1, 1, 8).setValues([[
          payload.id, payload.description, payload.amount, payload.date, 
          payload.category, payload.type, payload.status, payload.frequency
        ]]);
        found = true;
        break;
      }
    }

    if (!found) {
      sheet.appendRow([
        payload.id, payload.description, payload.amount, payload.date, 
        payload.category, payload.type, payload.status, payload.frequency
      ]);
    }
  } else if (action === 'delete') {
    var data = sheet.getDataRange().getValues();
    for (var i = 1; i < data.length; i++) {
      if (data[i][0] == payload.id) {
        sheet.deleteRow(i + 1);
        break;
      }
    }
  } else if (action === 'syncAll') {
    sheet.clear();
    sheet.appendRow(['id', 'description', 'amount', 'date', 'category', 'type', 'status', 'frequency']);
    payload.forEach(function(p) {
      sheet.appendRow([p.id, p.description, p.amount, p.date, p.category, p.type, p.status, p.frequency]);
    });
  }

  return ContentService.createTextOutput(JSON.stringify({result: 'success'}))
    .setMimeType(ContentService.MimeType.JSON);
}
```

