export default TransactionList;

export type TransactionType = 'Receita' | 'Despesa';
export type TransactionStatus = 'Pago' | 'Pendente';
export type TransactionFrequency = 'Fixo' | 'Esporádico';

export interface Transaction {
  id: string;
  descricao: string;
  valor: number;
  data: string; // Formato ISO yyyy-mm-dd
  categoria: string;
  tipo: TransactionType;
  status: TransactionStatus;
  frequencia: TransactionFrequency;
}

export interface MonthlyData {
  month: number;
  year: number;
  transactions: Transaction[];
}

export interface FinancialInsight {
  summary: string;
  recommendations: string[];
  alertLevel: 'low' | 'medium' | 'high';
}

export const CATEGORIES = {
  INCOME: ['Salário', 'Freelance', 'Investimento', 'Presente', 'Outro'],
  EXPENSE: ['Moradia', 'Alimentação', 'Transporte', 'Utilidades', 'Lazer', 'Saúde', 'Educação', 'Compras', 'Outro']
};

import { Transaction } from "../types";

const API_URL = "https://script.google.com/macros/s/AKfycbwkkqQLWU-fTZbx3cftjHHpd5xZ33dHNWldWwVSbwciWkDlIoZ7ngbqds_Gqjwq-uQZ/exec";

export const sheetsService = {
  async getAll(): Promise<Transaction[]> {
    if (!API_URL || API_URL.includes("SUA_URL_AQUI")) return [];
    try {
      const response = await fetch(API_URL, {
        method: "GET",
        mode: "cors",
        cache: "no-cache",
        redirect: "follow"
      });
      if (!response.ok) throw new Error(`Erro HTTP! status: ${response.status}`);
      const data = await response.json();

      if (!Array.isArray(data)) return [];

      // Garantir que os valores numéricos sejam tratados corretamente
      return data.map((t: any) => ({
        ...t,
        id: t.id ? t.id.toString() : "",
        valor: typeof t.valor === 'string' ? parseFloat(t.valor.replace(',', '.')) : (parseFloat(t.valor) || 0)
      }));
    } catch (error) {
      console.error("Erro ao carregar dados do Google Sheets:", error);
      throw error;
    }
  },

  async save(transaction: Transaction): Promise<boolean> {
    if (!API_URL || API_URL.includes("SUA_URL_AQUI")) return false;
    try {
      // Enviamos o objeto exatamente como o Apps Script espera receber
      console.log("Enviando para Sheets:", transaction);
      await fetch(API_URL, {
        method: "POST",
        mode: "no-cors",
        headers: { "Content-Type": "text/plain" },
        body: JSON.stringify({ action: "save", payload: transaction })
      });
      return true;
    } catch (error) {
      console.error("Erro ao salvar no Google Sheets:", error);
      return false;
    }
  },

  async delete(id: string): Promise<boolean> {
    if (!API_URL || API_URL.includes("SUA_URL_AQUI")) return false;
    try {
      await fetch(API_URL, {
        method: "POST",
        mode: "no-cors",
        headers: { "Content-Type": "text/plain" },
        body: JSON.stringify({ action: "delete", payload: { id } })
      });
      return true;
    } catch (error) {
      console.error("Erro ao deletar no Google Sheets:", error);
      return false;
    }
  },

  async syncAll(transactions: Transaction[]): Promise<boolean> {
    if (!API_URL || API_URL.includes("SUA_URL_AQUI")) return false;
    try {
      await fetch(API_URL, {
        method: "POST",
        mode: "no-cors",
        headers: { "Content-Type": "text/plain" },
        body: JSON.stringify({ action: "syncAll", payload: transactions })
      });
      return true;
    } catch (error) {
      console.error("Erro ao sincronizar Google Sheets:", error);
      return false;
    }
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { Transaction } from './types';
import Dashboard from './components/Dashboard';
import TransactionList from './components/TransactionList';
import GeminiInsights from './components/GeminiInsights';
import { sheetsService } from './services/googleSheetsService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'transactions'>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [syncError, setSyncError] = useState<string | null>(null);
  const [lastSync, setLastSync] = useState<Date | null>(null);

  const [selectedMonth, setSelectedMonth] = useState(new Date().getMonth());
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());

  const loadData = async (isManual = false) => {
    if (isManual) setIsRefreshing(true);
    else setIsLoading(true);

    setSyncError(null);
    try {
      const data = await sheetsService.getAll();
      if (data && data.length > 0) {
        setTransactions(data);
        setLastSync(new Date());
      } else {
        const saved = localStorage.getItem('ff_transactions');
        if (saved) setTransactions(JSON.parse(saved));
      }
    } catch (error) {
      console.error("Falha ao sincronizar. Usando cache local.");
      setSyncError("Falha na conexão com a nuvem.");
      const saved = localStorage.getItem('ff_transactions');
      if (saved) setTransactions(JSON.parse(saved));
    } finally {
      setIsLoading(false);
      setIsRefreshing(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const monthNames = [
    "Janeiro", "Fevereiro", "Março", "Abril", "Maio", "Junho",
    "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"
  ];

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const d = new Date(t.data);
      return d.getMonth() === selectedMonth && d.getFullYear() === selectedYear;
    });
  }, [transactions, selectedMonth, selectedYear]);

  const generateShortId = () => Math.floor(100000 + Math.random() * 900000).toString();

  const addTransaction = async (t: Omit<Transaction, 'id'>) => {
    const newTransaction = { ...t, id: generateShortId() } as Transaction;
    setTransactions(prev => [...prev, newTransaction]);
    await sheetsService.save(newTransaction);
  };

  const updateTransaction = async (updated: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updated.id ? updated : t));
    await sheetsService.save(updated);
  };

  const deleteTransaction = async (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
    await sheetsService.delete(id);
  };

  const toggleTransactionStatus = async (id: string) => {
    const target = transactions.find(t => t.id === id);
    if (!target) return;

    const updated = { ...target, status: target.status === 'Pago' ? 'Pendente' : 'Pago' } as Transaction;
    setTransactions(prev => prev.map(t => t.id === id ? updated : t));
    await sheetsService.save(updated);
  };

  const copyFromPreviousMonth = async () => {
    let prevMonth = selectedMonth - 1;
    let prevYear = selectedYear;
    if (prevMonth < 0) { prevMonth = 11; prevYear = selectedYear - 1; }

    const prevTransactions = transactions.filter(t => {
      const d = new Date(t.data);
      return d.getMonth() === prevMonth && d.getFullYear() === prevYear;
    });

    if (prevTransactions.length === 0) {
      alert(`Não foram encontrados lançamentos no mês anterior.`);
      return;
    }

    const newEntries: Transaction[] = prevTransactions.map(t => {
      const oldDate = new Date(t.data);
      const newDateObj = new Date(selectedYear, selectedMonth, oldDate.getDate());
      if (newDateObj.getMonth() !== selectedMonth) newDateObj.setDate(0); 

      return {
        ...t,
        id: generateShortId(),
        data: newDateObj.toISOString().split('T')[0],
        status: 'Pendente'
      };
    });

    const updatedList = [...transactions, ...newEntries];
    setTransactions(updatedList);
    await sheetsService.syncAll(updatedList);
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">
      <aside className="w-full md:w-64 bg-indigo-900 text-white flex flex-col md:sticky md:top-0 md:h-screen z-20">
        <div className="p-4 md:p-6 flex justify-between items-center md:block">
          <h1 className="text-xl md:text-2xl font-bold"><span className="text-indigo-400">Finance</span>Flow</h1>
          <div className="md:hidden">
            <GeminiInsights transactions={filteredTransactions} currentMonth={monthNames[selectedMonth]} mobileCompact />
          </div>
        </div>

