import React, { useState, useEffect } from 'react';
import { Transaction, TransactionType, TransactionStatus, TransactionFrequency, CATEGORIES } from '../types';

interface Props {
  transactions: Transaction[];
  onAdd: (t: Omit<Transaction, 'id'>) => void;
  onUpdate: (t: Transaction) => void;
  onDelete: (id: string) => void;
  onToggleStatus: (id: string) => void;
  onCopyPrevious: () => void;
  defaultMonth: number;
  defaultYear: number;
  monthName: string;
}

const TransactionList: React.FC<Props> = ({ transactions, onAdd, onUpdate, onDelete, onToggleStatus, onCopyPrevious, defaultMonth, defaultYear, monthName }) => {
  const [showModal, setShowModal] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  const getDefaultDate = () => {
    const now = new Date();
    const date = new Date(defaultYear, defaultMonth, now.getDate());
    return date.toISOString().split('T')[0];
  };

  const initialFormState = {
    descricao: '',
    valor: '',
    data: getDefaultDate(),
    categoria: 'Outro',
    tipo: 'Despesa' as TransactionType,
    status: 'Pendente' as TransactionStatus,
    frequencia: 'Fixo' as TransactionFrequency
  };

  const [formData, setFormData] = useState(initialFormState);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.descricao || !formData.valor) return;

    const payload = {
      descricao: formData.descricao,
      valor: parseFloat(formData.valor),
      data: formData.data,
      categoria: formData.categoria,
      tipo: formData.tipo,
      status: formData.status,
      frequencia: formData.frequencia
    };

    if (editingTransaction) onUpdate({ ...payload, id: editingTransaction.id });
    else onAdd(payload);

    setShowModal(false);
  };

  const handleExportCSV = () => {
    const headers = ["ID", "Descrição", "Valor", "Data", "Categoria", "Tipo", "Status", "Frequência"];
    const rows = transactions.map(t => [t.id, t.descricao, t.valor, t.data, t.categoria, t.tipo, t.status, t.frequencia]);
    const csvContent = "\uFEFF" + [headers, ...rows].map(e => e.join(";")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = `Relatorio_${monthName}.csv`;
    link.click();
  };

  const handleCopyWhatsApp = () => {
    let message = `📊 *Resumo Financeiro - ${monthName}*\n\n`;
    transactions.slice(0, 10).forEach(t => {
      message += `${t.tipo === 'Receita' ? '🟢' : '🔴'} ${t.descricao}: R$ ${t.valor.toLocaleString('pt-BR')}\n`;
    });
    navigator.clipboard.writeText(message).then(() => alert("Copiado para o WhatsApp!"));
  };

  return (
    <div className="space-y-4">
      <div className="flex flex-wrap gap-2 justify-end bg-white p-4 rounded-2xl shadow-sm">
        <button onClick={onCopyPrevious} className="px-3 py-2 bg-slate-100 rounded-xl text-xs font-bold">Importar Anterior</button>
        <button onClick={handleExportCSV} className="px-3 py-2 bg-emerald-100 text-emerald-700 rounded-xl text-xs font-bold">Excel</button>
        <button onClick={handleCopyWhatsApp} className="px-3 py-2 bg-green-500 text-white rounded-xl text-xs font-bold">WhatsApp</button>
        <button onClick={() => { setEditingTransaction(null); setFormData(initialFormState); setShowModal(true); }} className="px-4 py-2 bg-indigo-600 text-white rounded-xl text-xs font-bold">Novo Lançamento</button>
      </div>

      <div className="bg-white rounded-2xl shadow-sm overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 text-[10px] uppercase font-bold text-slate-400">
            <tr>
              <th className="p-4">ID</th><th className="p-4">Descrição</th><th className="p-4">Status</th><th className="p-4">Valor</th><th className="p-4 text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {transactions.map(t => (
              <tr key={t.id} className="text-sm">
                <td className="p-4 font-mono text-xs text-slate-400">#{t.id}</td>
                <td className="p-4 font-bold">{t.descricao} <br/><span className="text-[10px] font-normal text-slate-400">{t.categoria} • {t.data}</span></td>
                <td className="p-4"><button onClick={() => onToggleStatus(t.id)} className={`px-2 py-1 rounded-full text-[10px] font-bold ${t.status === 'Pago' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'}`}>{t.status}</button></td>
                <td className={`p-4 font-bold ${t.tipo === 'Receita' ? 'text-emerald-600' : 'text-rose-600'}`}>R$ {t.valor.toLocaleString('pt-BR', {minimumFractionDigits:2})}</td>
                <td className="p-4 text-right">
                   <button onClick={() => { setEditingTransaction(t); setFormData({descricao:t.descricao, valor:t.valor.toString(), data:t.data, categoria:t.categoria, tipo:t.tipo, status:t.status, frequencia:t.frequencia}); setShowModal(true); }} className="p-1 text-slate-400 hover:text-indigo-600">Edit</button>
                   <button onClick={() => onDelete(t.id)} className="p-1 text-slate-400 hover:text-rose-600 ml-2">Del</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {showModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-[100] p-4">
          <form onSubmit={handleSubmit} className="bg-white rounded-3xl w-full max-w-md p-6 space-y-4 shadow-2xl">
            <h3 className="text-xl font-bold">{editingTransaction ? 'Editar' : 'Novo'} Lançamento</h3>
            <div className="flex p-1 bg-slate-100 rounded-xl">
              <button type="button" onClick={() => setFormData({...formData, tipo: 'Despesa'})} className={`flex-1 py-2 rounded-lg text-sm font-bold ${formData.tipo === 'Despesa' ? 'bg-white shadow' : ''}`}>Despesa</button>
              <button type="button" onClick={() => setFormData({...formData, tipo: 'Receita'})} className={`flex-1 py-2 rounded-lg text-sm font-bold ${formData.tipo === 'Receita' ? 'bg-white shadow' : ''}`}>Receita</button>
            </div>
            <input type="text" value={formData.descricao} onChange={e => setFormData({...formData, descricao: e.target.value})} placeholder="Descrição" className="w-full p-3 border rounded-xl" />
            <input type="number" step="0.01" value={formData.valor} onChange={e => setFormData({...formData, valor: e.target.value})} placeholder="Valor R$" className="w-full p-3 border rounded-xl" />
            <input type="date" value={formData.data} onChange={e => setFormData({...formData, data: e.target.value})} className="w-full p-3 border rounded-xl" />
            <select value={formData.categoria} onChange={e => setFormData({...formData, categoria: e.target.value})} className="w-full p-3 border rounded-xl">
              {(formData.tipo === 'Receita' ? CATEGORIES.INCOME : CATEGORIES.EXPENSE).map(c => <option key={c} value={c}>{c}</option>)}
            </select>
            <div className="flex gap-2">
              <button type="button" onClick={() => setShowModal(false)} className="flex-1 p-3 bg-slate-100 rounded-xl font-bold">Cancelar</button>
              <button type="submit" className="flex-1 p-3 bg-indigo-600 text-white rounded-xl font-bold">Salvar</button>
            </div>
          </form>
        </div>
      )}
    </div>
  );
};

