        <header className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
          <div>
            <h2 className="text-2xl font-extrabold text-slate-800">{activeTab === 'dashboard' ? 'Painel de Controle' : 'Seus Lançamentos'}</h2>
            <p className="text-slate-400 text-xs font-medium uppercase tracking-wider mt-1">{monthNames[selectedMonth]} de {selectedYear}</p>
          </div>

          <div className="flex flex-wrap items-center gap-2 w-full md:w-auto">
