import React, { useState, useEffect } from 'react';
import { Transaction, TransactionType, TransactionStatus, TransactionFrequency, CATEGORIES } from '../types';

interface Props {
  transactions: Transaction[];
  onAdd: (t: Omit<Transaction, 'id'>) => void;
  onUpdate: (t: Transaction) => void;
  onDelete: (id: string) => void;
  onToggleStatus: (id: string) => void;
  onCopyPrevious: () => void;
  defaultMonth: number;
  defaultYear: number;
  monthName: string;
}

const TransactionList: React.FC<Props> = ({ transactions, onAdd, onUpdate, onDelete, onToggleStatus, onCopyPrevious, defaultMonth, defaultYear, monthName }) => {
  const [showModal, setShowModal] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  const getDefaultDate = () => {
    const now = new Date();
    return new Date(defaultYear, defaultMonth, now.getDate()).toISOString().split('T')[0];
  };

  const initialFormState = {
    descricao: '', valor: '', data: getDefaultDate(), categoria: 'Outro', tipo: 'Despesa' as TransactionType, status: 'Pendente' as TransactionStatus, frequencia: 'Fixo' as TransactionFrequency
  };

  const [formData, setFormData] = useState(initialFormState);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.descricao || !formData.valor) return;
    const payload = { ...formData, valor: parseFloat(formData.valor) };
    if (editingTransaction) onUpdate({ ...payload, id: editingTransaction.id });
    else onAdd(payload);
    setShowModal(false);
  };

  const handleExportCSV = () => {
    const headers = ["ID", "Descrição", "Valor", "Data", "Categoria", "Tipo", "Status", "Frequência"];
    const rows = transactions.map(t => [t.id, t.descricao, t.valor, t.data, t.categoria, t.tipo, t.status, t.frequencia]);
    const csvContent = "\uFEFF" + [headers, ...rows].map(e => e.join(";")).join("\n");
    const link = document.createElement("a");
    link.href = URL.createObjectURL(new Blob([csvContent], { type: 'text/csv;charset=utf-8;' }));
    link.download = `Relatorio_${monthName}.csv`;
    link.click();
  };

  const handleCopyWhatsApp = () => {
    let msg = `📊 *Resumo ${monthName}*\n\n`;
    transactions.slice(0, 10).forEach(t => msg += `${t.tipo === 'Receita' ? '🟢' : '🔴'} ${t.descricao}: R$ ${t.valor.toLocaleString('pt-BR')}\n`);
    navigator.clipboard.writeText(msg).then(() => alert("Copiado!"));
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-wrap items-center justify-between gap-4 bg-white p-4 rounded-2xl border border-gray-200 shadow-sm">
        <div className="flex gap-2">
          <button onClick={onCopyPrevious} className="px-4 py-2 bg-gray-50 text-slate-600 rounded-lg text-xs font-bold border border-gray-100 hover:bg-gray-100 transition">Importar Anterior</button>
          <button onClick={handleExportCSV} className="px-4 py-2 bg-gray-50 text-slate-600 rounded-lg text-xs font-bold border border-gray-100 hover:bg-gray-100 transition">Excel</button>
        </div>

        <div className="flex gap-2">
          <button onClick={handleCopyWhatsApp} className="px-4 py-2 bg-emerald-50 text-emerald-600 rounded-lg text-xs font-bold border border-emerald-100 hover:bg-emerald-100 transition">WhatsApp</button>
          <button onClick={() => { setEditingTransaction(null); setFormData(initialFormState); setShowModal(true); }} className="px-6 py-2 bg-brand-500 text-white rounded-lg text-sm font-extrabold shadow-lg shadow-brand-100 hover:bg-brand-600 transition active:scale-95">
             + Novo Lançamento
          </button>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-gray-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left whitespace-nowrap">
            <thead className="bg-gray-50/50 text-[10px] uppercase font-bold text-slate-400">
              <tr>
                <th className="px-6 py-4">Status</th>
                <th className="px-6 py-4">Lançamento</th>
                <th className="px-6 py-4">Categoria</th>
                <th className="px-6 py-4">Valor</th>
                <th className="px-6 py-4 text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {transactions.length > 0 ? transactions.map(t => (
                <tr key={t.id} className="hover:bg-gray-50/50 transition">
                  <td className="px-6 py-4">
                    <button onClick={() => onToggleStatus(t.id)} className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-wider ${t.status === 'Pago' ? 'bg-brand-50 text-brand-600' : 'bg-orange-50 text-orange-600'}`}>
                      {t.status}
                    </button>
                  </td>
                  <td className="px-6 py-4">
                    <div className="font-bold text-slate-800 text-sm">{t.descricao}</div>
                    <div className="text-[10px] text-slate-400 font-medium">{t.data} • #{t.id}</div>
                  </td>
                  <td className="px-6 py-4 text-xs font-bold text-slate-500">{t.categoria}</td>
                  <td className={`px-6 py-4 font-black text-sm ${t.tipo === 'Receita' ? 'text-brand-500' : 'text-rose-500'}`}>
                    R$ {t.valor.toLocaleString('pt-BR', {minimumFractionDigits:2})}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button onClick={() => { setEditingTransaction(t); setFormData({descricao:t.descricao, valor:t.valor.toString(), data:t.data, categoria:t.categoria, tipo:t.tipo, status:t.status, frequencia:t.frequencia}); setShowModal(true); }} className="p-2 text-slate-300 hover:text-brand-500 transition">
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z"></path></svg>
                    </button>
                    <button onClick={() => onDelete(t.id)} className="p-2 text-slate-300 hover:text-rose-500 transition ml-1">
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                    </button>
                  </td>
                </tr>
              )) : <tr><td colSpan={5} className="px-6 py-20 text-center text-slate-300 font-medium italic">Nenhum lançamento encontrado.</td></tr>}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm flex items-center justify-center z-[100] p-4">
          <form onSubmit={handleSubmit} className="bg-white rounded-3xl w-full max-w-md p-8 space-y-5 shadow-2xl animate-in zoom-in-95 duration-200">
            <h3 className="text-xl font-black text-slate-800">{editingTransaction ? 'Editar' : 'Novo'} Lançamento</h3>

            <div className="flex p-1.5 bg-gray-100 rounded-2xl">
              <button type="button" onClick={() => setFormData({...formData, tipo: 'Despesa'})} className={`flex-1 py-2.5 rounded-xl text-xs font-black transition ${formData.tipo === 'Despesa' ? 'bg-white text-rose-600 shadow-sm' : 'text-slate-400'}`}>DESPESA</button>
              <button type="button" onClick={() => setFormData({...formData, tipo: 'Receita'})} className={`flex-1 py-2.5 rounded-xl text-xs font-black transition ${formData.tipo === 'Receita' ? 'bg-white text-brand-600 shadow-sm' : 'text-slate-400'}`}>RECEITA</button>
            </div>

            <div className="space-y-4">
              <input type="text" value={formData.descricao} onChange={e => setFormData({...formData, descricao: e.target.value})} placeholder="Descrição" className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:border-brand-500 outline-none font-bold text-slate-800" />
              <input type="number" step="0.01" value={formData.valor} onChange={e => setFormData({...formData, valor: e.target.value})} placeholder="R$ 0,00" className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:border-brand-500 outline-none font-black text-2xl text-slate-800" />
              <div className="grid grid-cols-2 gap-3">
                <input type="date" value={formData.data} onChange={e => setFormData({...formData, data: e.target.value})} className="p-4 bg-gray-50 border border-gray-100 rounded-2xl outline-none text-xs font-bold text-slate-600" />
                <select value={formData.categoria} onChange={e => setFormData({...formData, categoria: e.target.value})} className="p-4 bg-gray-50 border border-gray-100 rounded-2xl outline-none text-xs font-bold text-slate-600">
                  {(formData.tipo === 'Receita' ? CATEGORIES.INCOME : CATEGORIES.EXPENSE).map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
            </div>

            <div className="flex gap-3 pt-4">
              <button type="button" onClick={() => setShowModal(false)} className="flex-1 p-4 bg-gray-50 text-slate-400 rounded-2xl font-bold text-sm hover:bg-gray-100 transition">Cancelar</button>
              <button type="submit" className={`flex-1 p-4 text-white rounded-2xl font-black text-sm shadow-lg transition active:scale-95 ${formData.tipo === 'Receita' ? 'bg-brand-500 shadow-brand-100 hover:bg-brand-600' : 'bg-rose-500 shadow-rose-100 hover:bg-rose-600'}`}>
                {editingTransaction ? 'Atualizar' : 'Confirmar'}
              </button>
            </div>
          </form>
        </div>
      )}
    </div>
  );
};

export default TransactionList;

import React, { useState, useEffect, useMemo } from 'react';
import { Transaction } from './types';
import Dashboard from './components/Dashboard';
import TransactionList from './components/TransactionList';
import GeminiInsights from './components/GeminiInsights';
import { sheetsService } from './services/googleSheetsService';

const App: React.FC = () => {
  const [isHome, setIsHome] = useState(true);
  const [hideValues, setHideValues] = useState(true); // Inicia ocultado conforme pedido
  const [activeTab, setActiveTab] = useState<'dashboard' | 'transactions'>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isRefreshing, setIsRefreshing] = useState(false);

  const [selectedMonth, setSelectedMonth] = useState(new Date().getMonth());
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());

  const loadData = async (isManual = false) => {
    if (isManual) setIsRefreshing(true);
    else setIsLoading(true);

    try {
      const data = await sheetsService.getAll();
      if (data && data.length > 0) {
        setTransactions(data);
      } else {
        const saved = localStorage.getItem('ff_transactions');
        if (saved) setTransactions(JSON.parse(saved));
      }
    } catch (error) {
      const saved = localStorage.getItem('ff_transactions');
      if (saved) setTransactions(JSON.parse(saved));
    } finally {
      setIsLoading(false);
      setIsRefreshing(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const monthNames = ["Janeiro", "Fevereiro", "Março", "Abril", "Maio", "Junho", "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"];

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const d = new Date(t.data);
      return d.getMonth() === selectedMonth && d.getFullYear() === selectedYear;
    });
  }, [transactions, selectedMonth, selectedYear]);

  const generateShortId = () => Math.floor(100000 + Math.random() * 900000).toString();

  const addTransaction = async (t: Omit<Transaction, 'id'>) => {
    const newTransaction = { ...t, id: generateShortId() } as Transaction;
    setTransactions(prev => [...prev, newTransaction]);
    await sheetsService.save(newTransaction);
  };

  const updateTransaction = async (updated: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updated.id ? updated : t));
    await sheetsService.save(updated);
  };

  const deleteTransaction = async (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
    await sheetsService.delete(id);
  };

  const toggleTransactionStatus = async (id: string) => {
    const target = transactions.find(t => t.id === id);
    if (!target) return;
    const updated = { ...target, status: target.status === 'Pago' ? 'Pendente' : 'Pago' } as Transaction;
    setTransactions(prev => prev.map(t => t.id === id ? updated : t));
    await sheetsService.save(updated);
  };

  const copyFromPreviousMonth = async () => {
    let prevMonth = selectedMonth - 1;
    let prevYear = selectedYear;
    if (prevMonth < 0) { prevMonth = 11; prevYear = selectedYear - 1; }
    const prevTransactions = transactions.filter(t => {
      const d = new Date(t.data);
      return d.getMonth() === prevMonth && d.getFullYear() === prevYear;
    });
    if (prevTransactions.length === 0) return alert(`Nenhum dado no mês anterior.`);
    const newEntries: Transaction[] = prevTransactions.map(t => ({
      ...t, id: generateShortId(), data: new Date(selectedYear, selectedMonth, new Date(t.data).getDate()).toISOString().split('T')[0], status: 'Pendente'
    }));
    const updatedList = [...transactions, ...newEntries];
    setTransactions(updatedList);
    await sheetsService.syncAll(updatedList);
  };

  // TELA DE INÍCIO
  if (isHome) {
    return (
      <div className="min-h-screen bg-white flex flex-col items-center justify-center p-6 text-center animate-enter">
        <div className="w-20 h-20 bg-brand-500 rounded-3xl flex items-center justify-center mb-8 shadow-xl shadow-brand-100">
          <div className="w-10 h-10 border-4 border-white rounded-full border-t-transparent"></div>
        </div>
        <h1 className="text-4xl font-black text-slate-800 mb-2">Finance<span className="text-brand-500">Peres</span></h1>
        <p className="text-slate-400 max-w-sm mb-12">Seu controle financeiro pessoal simplificado e inteligente.</p>
        <button 
          onClick={() => setIsHome(false)}
          className="w-full max-w-xs py-4 bg-brand-500 text-white rounded-2xl font-black text-lg shadow-xl shadow-brand-100 hover:bg-brand-600 transition active:scale-95"
        >
          Entrar no App
        </button>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-[#f5f7f8]">
      <aside className="w-full md:w-64 bg-white border-r border-gray-200 flex flex-col md:sticky md:top-0 md:h-screen z-20">
        <div className="p-6 flex justify-between items-center md:block">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-brand-500 rounded-full flex items-center justify-center">
              <div className="w-4 h-4 border-2 border-white rounded-full border-t-transparent"></div>
            </div>
            <h1 className="text-xl font-extrabold tracking-tight text-slate-800">
              Finance<span className="text-brand-500">Peres</span>
            </h1>
          </div>
          <div className="md:hidden flex items-center gap-3">
             <button onClick={() => setHideValues(!hideValues)} className="p-2 text-slate-400">
               {hideValues ? (
                 <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l3.59 3.59m0 0A9.953 9.953 0 0112 5c4.478 0 8.268 2.943 9.543 7a10.025 10.025 0 01-4.132 5.411m0 0L21 21"></path></svg>
               ) : (
                 <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z"></path></svg>
               )}
             </button>
             <GeminiInsights transactions={filteredTransactions} currentMonth={monthNames[selectedMonth]} mobileCompact />
          </div>
        </div>

        <nav className="flex md:flex-col px-3 space-x-1 md:space-x-0 md:space-y-1">
          <button onClick={() => setActiveTab('dashboard')} className={`flex-1 md:flex-none flex items-center gap-3 px-4 py-3 rounded-lg font-bold text-sm transition ${activeTab === 'dashboard' ? 'bg-brand-50 text-brand-600' : 'text-slate-500 hover:bg-gray-50'}`}>
             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6a2 2 0 012-2h2a2 2 0 012 2v12a2 2 0 01-2 2H6a2 2 0 01-2-2V6zM14 6a2 2 0 012-2h2a2 2 0 012 2v12a2 2 0 01-2 2h-2a2 2 0 01-2-2V6z"></path></svg>
             Painel
          </button>
          <button onClick={() => setActiveTab('transactions')} className={`flex-1 md:flex-none flex items-center gap-3 px-4 py-3 rounded-lg font-bold text-sm transition ${activeTab === 'transactions' ? 'bg-brand-50 text-brand-600' : 'text-slate-500 hover:bg-gray-50'}`}>
             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01"></path></svg>
             Lançamentos
          </button>
        </nav>

        <div className="hidden md:block p-6 mt-auto">
          <GeminiInsights transactions={filteredTransactions} currentMonth={monthNames[selectedMonth]} />
        </div>
      </aside>

      <main className="flex-1 p-4 md:p-8">
        {(isLoading || isRefreshing) && <div className="fixed top-0 left-0 w-full h-1 bg-brand-500 z-[100] animate-pulse"></div>}

        <header className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
          <div className="flex items-center gap-4">
            <div>
              <h2 className="text-2xl font-extrabold text-slate-800">{activeTab === 'dashboard' ? 'Painel de Controle' : 'Lançamentos'}</h2>
              <p className="text-slate-400 text-[10px] font-bold uppercase tracking-wider mt-1">{monthNames[selectedMonth]} de {selectedYear}</p>
            </div>
            <button onClick={() => setHideValues(!hideValues)} className="hidden md:flex items-center gap-2 px-3 py-1.5 bg-white border border-gray-200 rounded-lg text-slate-400 hover:text-brand-500 transition shadow-sm">
              {hideValues ? (
                <>
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l3.59 3.59m0 0A9.953 9.953 0 0112 5c4.478 0 8.268 2.943 9.543 7a10.025 10.025 0 01-4.132 5.411m0 0L21 21"></path></svg>
                  <span className="text-[10px] font-bold">EXIBIR</span>
                </>
              ) : (
                <>
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z"></path></svg>
                  <span className="text-[10px] font-bold">OCULTAR</span>
                </>
              )}
            </button>
          </div>

          <div className="flex flex-wrap items-center gap-2 w-full md:w-auto">
            <button onClick={() => loadData(true)} className="p-2.5 bg-white border border-gray-200 rounded-xl text-slate-500 hover:text-brand-500 transition shadow-sm">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path></svg>
            </button>
            <div className="flex bg-white p-1 rounded-xl border border-gray-200 shadow-sm">
              <select value={selectedMonth} onChange={(e) => setSelectedMonth(parseInt(e.target.value))} className="bg-transparent text-slate-700 text-xs font-bold px-3 py-1 outline-none">
                {monthNames.map((name, i) => <option key={i} value={i}>{name}</option>)}
              </select>
              <div className="w-px h-4 bg-gray-200 self-center"></div>
              <select value={selectedYear} onChange={(e) => setSelectedYear(parseInt(e.target.value))} className="bg-transparent text-slate-700 text-xs font-bold px-3 py-1 outline-none">
                <option value={2024}>2024</option><option value={2025}>2025</option>
              </select>
            </div>
          </div>
        </header>

        <div className="animate-in fade-in slide-in-from-bottom-2 duration-500">
          {activeTab === 'dashboard' ? (
            <Dashboard 
              transactions={filteredTransactions} 
              hideValues={hideValues} 
              monthName={monthNames[selectedMonth]}
            />
          ) : (
            <TransactionList 
              transactions={filteredTransactions} 
              onAdd={addTransaction} 
              onUpdate={updateTransaction} 
              onDelete={deleteTransaction} 
              onToggleStatus={toggleTransactionStatus} 
              onCopyPrevious={copyFromPreviousMonth} 
              defaultMonth={selectedMonth} 
              defaultYear={selectedYear} 
              monthName={monthNames[selectedMonth]}
              hideValues={hideValues}
            />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  PieChart, Pie, Cell, Legend 
} from 'recharts';
