import { GoogleGenAI, Type } from "@google/genai";
import { Transaction } from "../types";

export const getFinancialInsights = async (transactions: Transaction[], currentMonth: string) => {
  // Verificação de segurança para evitar crash em ambientes onde process.env pode não estar definido imediatamente
  const apiKey = typeof process !== 'undefined' ? process.env.API_KEY : '';
  if (!apiKey) {
    throw new Error("API Key não configurada. Verifique as configurações de ambiente.");
  }

  const ai = new GoogleGenAI({ apiKey });

  const summary = transactions.reduce((acc: { income: number; expense: number }, t) => {
    if (t.tipo === 'Receita') {
      acc.income += t.valor;
    } else {
      acc.expense += t.valor;
    }
    return acc;
  }, { income: 0, expense: 0 });

  const categoryBreakdown = transactions
    .filter(t => t.tipo === 'Despesa')
    .reduce((acc: any, t) => {
      acc[t.categoria] = (acc[t.categoria] || 0) + t.valor;
      return acc;
    }, {});

  const prompt = `
    Analise as seguintes finanças pessoais do mês de ${currentMonth}:
    - Total de Receita: R$ ${summary.income.toFixed(2)}
    - Total de Despesas: R$ ${summary.expense.toFixed(2)}
    - Saldo: R$ ${(summary.income - summary.expense).toFixed(2)}
    - Gastos por Categoria: ${JSON.stringify(categoryBreakdown)}

    Por favor, forneça um resumo amigável e 3 recomendações acionáveis para melhorar a saúde financeira.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING, description: "A friendly summary of the month's financial performance in Portuguese." },
            recommendations: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING },
              description: "3 actionable tips in Portuguese."
            },
            alertLevel: { 
              type: Type.STRING, 
              enum: ['low', 'medium', 'high'],
              description: "The level of financial concern."
            }
          },
          required: ["summary", "recommendations", "alertLevel"]
        }
      }
    });

    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Error fetching Gemini insights:", error);
    throw error;
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { Transaction } from './types';
import Dashboard from './components/Dashboard';
import TransactionList from './components/TransactionList';
import GeminiInsights from './components/GeminiInsights';
import { sheetsService } from './services/googleSheetsService';

const App: React.FC = () => {
  const [isHome, setIsHome] = useState(true);
  const [hideValues, setHideValues] = useState(true);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'transactions'>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [syncStatus, setSyncStatus] = useState<'online' | 'offline' | 'syncing'>('syncing');

  const [selectedMonth, setSelectedMonth] = useState(new Date().getMonth());
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());

  const loadData = async (isManual = false) => {
    if (isManual) setIsRefreshing(true);
    else setIsLoading(true);
    setSyncStatus('syncing');

    try {
      const data = await sheetsService.getAll();
      if (data && data.length > 0) {
        setTransactions(data);
        localStorage.setItem('ff_transactions', JSON.stringify(data));
        setSyncStatus('online');
      } else {
        const saved = localStorage.getItem('ff_transactions');
        if (saved) setTransactions(JSON.parse(saved));
        setSyncStatus('online');
      }
    } catch (error) {
      console.error("Sync error:", error);
      const saved = localStorage.getItem('ff_transactions');
      if (saved) setTransactions(JSON.parse(saved));
      setSyncStatus('offline');
    } finally {
      setIsLoading(false);
      setIsRefreshing(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const monthNames = ["Janeiro", "Fevereiro", "Março", "Abril", "Maio", "Junho", "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"];

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const d = new Date(t.data);
      return d.getMonth() === selectedMonth && d.getFullYear() === selectedYear;
    });
  }, [transactions, selectedMonth, selectedYear]);

  const generateShortId = () => Math.floor(100000 + Math.random() * 900000).toString();

  const addTransaction = async (t: Omit<Transaction, 'id'>) => {
    const newTransaction = { ...t, id: generateShortId() } as Transaction;
    const newList = [...transactions, newTransaction];
    setTransactions(newList);
    localStorage.setItem('ff_transactions', JSON.stringify(newList));
    const success = await sheetsService.save(newTransaction);
    setSyncStatus(success ? 'online' : 'offline');
  };

  const updateTransaction = async (updated: Transaction) => {
    const newList = transactions.map(t => t.id === updated.id ? updated : t);
    setTransactions(newList);
    localStorage.setItem('ff_transactions', JSON.stringify(newList));
    const success = await sheetsService.save(updated);
    setSyncStatus(success ? 'online' : 'offline');
  };

  const deleteTransaction = async (id: string) => {
    const newList = transactions.filter(t => t.id !== id);
    setTransactions(newList);
    localStorage.setItem('ff_transactions', JSON.stringify(newList));
    const success = await sheetsService.delete(id);
    setSyncStatus(success ? 'online' : 'offline');
  };

  const toggleTransactionStatus = async (id: string) => {
    const target = transactions.find(t => t.id === id);
    if (!target) return;
    const updated = { ...target, status: target.status === 'Pago' ? 'Pendente' : 'Pago' } as Transaction;
    const newList = transactions.map(t => t.id === id ? updated : t);
    setTransactions(newList);
    localStorage.setItem('ff_transactions', JSON.stringify(newList));
    const success = await sheetsService.save(updated);
    setSyncStatus(success ? 'online' : 'offline');
  };

  const copyFromPreviousMonth = async () => {
    let prevMonth = selectedMonth - 1;
    let prevYear = selectedYear;
    if (prevMonth < 0) { prevMonth = 11; prevYear = selectedYear - 1; }
    const prevTransactions = transactions.filter(t => {
      const d = new Date(t.data);
      return d.getMonth() === prevMonth && d.getFullYear() === prevYear;
    });
    if (prevTransactions.length === 0) return alert(`Nenhum dado no mês anterior.`);
    const newEntries: Transaction[] = prevTransactions.map(t => ({
      ...t, id: generateShortId(), data: new Date(selectedYear, selectedMonth, new Date(t.data).getDate()).toISOString().split('T')[0], status: 'Pendente'
    }));
    const updatedList = [...transactions, ...newEntries];
    setTransactions(updatedList);
    localStorage.setItem('ff_transactions', JSON.stringify(updatedList));
    const success = await sheetsService.syncAll(updatedList);
    setSyncStatus(success ? 'online' : 'offline');
  };

  if (isHome) {
    return (
      <div className="min-h-screen bg-white flex flex-col items-center justify-center p-6 text-center animate-enter">
        <div className="w-20 h-20 bg-brand-500 rounded-3xl flex items-center justify-center mb-8 shadow-xl shadow-brand-100">
          <div className="w-10 h-10 border-4 border-white rounded-full border-t-transparent"></div>
        </div>
        <h1 className="text-4xl font-black text-slate-800 mb-2">Finance<span className="text-brand-500">Peres</span></h1>
        <p className="text-slate-400 max-w-sm mb-12">Seu controle financeiro pessoal simplificado e inteligente.</p>
        <button 
          onClick={() => setIsHome(false)}
          className="w-full max-w-xs py-4 bg-brand-500 text-white rounded-2xl font-black text-lg shadow-xl shadow-brand-100 hover:bg-brand-600 transition active:scale-95"
        >
          Entrar no App
        </button>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-[#f5f7f8]">
      <aside className="w-full md:w-64 bg-white border-r border-gray-200 flex flex-col md:sticky md:top-0 md:h-screen z-20">
        <div className="p-6 flex justify-between items-center md:block">
          <div className="flex items-center gap-2 mb-6">
            <div className="w-8 h-8 bg-brand-500 rounded-full flex items-center justify-center">
              <div className="w-4 h-4 border-2 border-white rounded-full border-t-transparent"></div>
            </div>
            <h1 className="text-xl font-extrabold tracking-tight text-slate-800">
              Finance<span className="text-brand-500">Peres</span>
            </h1>
          </div>

          <div className={`flex items-center gap-3 p-3 rounded-2xl border transition-all ${syncStatus === 'online' ? 'bg-emerald-50 border-emerald-100' : syncStatus === 'syncing' ? 'bg-amber-50 border-amber-100 animate-pulse' : 'bg-rose-50 border-rose-100'}`}>
            <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${syncStatus === 'online' ? 'bg-emerald-500 text-white' : syncStatus === 'syncing' ? 'bg-amber-400 text-white' : 'bg-rose-500 text-white'}`}>
              {syncStatus === 'online' ? (
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 15a4 4 0 004 4h9a5 5 0 10-.1-9.999 5.002 5.002 0 10-9.78 2.096A4.001 4.001 0 003 15z"></path></svg>
              ) : syncStatus === 'syncing' ? (
                <svg className="w-5 h-5 animate-spin" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path></svg>
              ) : (
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M18.364 5.636l-1.414 1.414m-10.95 10.95l-1.414 1.414M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5.636 5.636l12.728 12.728"></path></svg>
              )}
            </div>
            <div>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</p>
              <p className={`text-xs font-black uppercase tracking-tight ${syncStatus === 'online' ? 'text-emerald-600' : syncStatus === 'syncing' ? 'text-amber-600' : 'text-rose-600'}`}>
                {syncStatus === 'online' ? 'Sincronizado' : syncStatus === 'syncing' ? 'Salvando...' : 'Modo Offline'}
              </p>
            </div>
          </div>

          <div className="md:hidden flex items-center gap-3 mt-4">
             <button onClick={() => setHideValues(!hideValues)} className="p-2 text-slate-400">
               {hideValues ? (
                 <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l3.59 3.59m0 0A9.953 9.953 0 0112 5c4.478 0 8.268 2.943 9.543 7a10.025 10.025 0 01-4.132 5.411m0 0L21 21"></path></svg>
               ) : (
                 <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z"></path></svg>
               )}
             </button>
             <GeminiInsights transactions={filteredTransactions} currentMonth={monthNames[selectedMonth]} mobileCompact />
          </div>
        </div>

        <nav className="flex md:flex-col px-3 mt-4 space-x-1 md:space-x-0 md:space-y-1">
          <button onClick={() => setActiveTab('dashboard')} className={`flex-1 md:flex-none flex items-center gap-3 px-4 py-3 rounded-xl font-bold text-sm transition ${activeTab === 'dashboard' ? 'bg-brand-50 text-brand-600' : 'text-slate-500 hover:bg-gray-50'}`}>
             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6a2 2 0 012-2h2a2 2 0 012 2v12a2 2 0 01-2 2H6a2 2 0 01-2-2V6zM14 6a2 2 0 012-2h2a2 2 0 012 2v12a2 2 0 01-2 2h-2a2 2 0 01-2-2V6z"></path></svg>
             Painel
          </button>
          <button onClick={() => setActiveTab('transactions')} className={`flex-1 md:flex-none flex items-center gap-3 px-4 py-3 rounded-xl font-bold text-sm transition ${activeTab === 'transactions' ? 'bg-brand-50 text-brand-600' : 'text-slate-500 hover:bg-gray-50'}`}>
             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01"></path></svg>
             Lançamentos
          </button>
        </nav>

        <div className="hidden md:block p-6 mt-auto">
          <GeminiInsights transactions={filteredTransactions} currentMonth={monthNames[selectedMonth]} />
        </div>
      </aside>

      <main className="flex-1 p-4 md:p-8">
        {(isLoading || isRefreshing) && <div className="fixed top-0 left-0 w-full h-1 bg-brand-500 z-[100] animate-pulse"></div>}

        <header className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
          <div className="flex items-center gap-4">
            <div>
              <h2 className="text-2xl font-extrabold text-slate-800">{activeTab === 'dashboard' ? 'Painel de Controle' : 'Lançamentos'}</h2>
              <p className="text-slate-400 text-[10px] font-bold uppercase tracking-wider mt-1">{monthNames[selectedMonth]} de {selectedYear}</p>
            </div>
            <button onClick={() => setHideValues(!hideValues)} className="hidden md:flex items-center gap-2 px-3 py-1.5 bg-white border border-gray-200 rounded-lg text-slate-400 hover:text-brand-500 transition shadow-sm">
              {hideValues ? (
                <>
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l3.59 3.59m0 0A9.953 9.953 0 0112 5c4.478 0 8.268 2.943 9.543 7a10.025 10.025 0 01-4.132 5.411m0 0L21 21"></path></svg>
                  <span className="text-[10px] font-bold">EXIBIR</span>
                </>
              ) : (
                <>
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z"></path></svg>
                  <span className="text-[10px] font-bold">OCULTAR</span>
                </>
              )}
            </button>
          </div>

          <div className="flex flex-wrap items-center gap-2 w-full md:w-auto">
            <button onClick={() => loadData(true)} className="p-2.5 bg-white border border-gray-200 rounded-xl text-slate-500 hover:text-brand-500 transition shadow-sm">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path></svg>
            </button>
            <div className="flex bg-white p-1 rounded-xl border border-gray-200 shadow-sm">
              <select value={selectedMonth} onChange={(e) => setSelectedMonth(parseInt(e.target.value))} className="bg-transparent text-slate-700 text-xs font-bold px-3 py-1 outline-none">
                {monthNames.map((name, i) => <option key={i} value={i}>{name}</option>)}
              </select>
              <div className="w-px h-4 bg-gray-200 self-center"></div>
              <select value={selectedYear} onChange={(e) => setSelectedYear(parseInt(e.target.value))} className="bg-transparent text-slate-700 text-xs font-bold px-3 py-1 outline-none">
                <option value={2024}>2024</option><option value={2025}>2025</option>
              </select>
            </div>
          </div>
        </header>

        <div className="animate-in fade-in slide-in-from-bottom-2 duration-500">
          {activeTab === 'dashboard' ? (
            <Dashboard 
              transactions={filteredTransactions} 
              hideValues={hideValues} 
              monthName={monthNames[selectedMonth]}
            />
          ) : (
            <TransactionList 
              transactions={filteredTransactions} 
              onAdd={addTransaction} 
              onUpdate={updateTransaction} 
              onDelete={deleteTransaction} 
              onToggleStatus={toggleTransactionStatus} 
              onCopyPrevious={copyFromPreviousMonth} 
              defaultMonth={selectedMonth} 
              defaultYear={selectedYear} 
              monthName={monthNames[selectedMonth]}
              hideValues={hideValues}
            />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  PieChart, Pie, Cell, Legend 
} from 'recharts';
import { Transaction } from '../types';

interface Props {
  transactions: Transaction[];
  hideValues: boolean;
  monthName: string;
}

const COLORS = ['#1ebf61', '#34d399', '#f59e0b', '#ef4444', '#10b981', '#f97316', '#06b6d4', '#8b5cf6'];

const Dashboard: React.FC<Props> = ({ transactions, hideValues, monthName }) => {
  const [excelStatus, setExcelStatus] = useState<'idle' | 'active'>('idle');
  const [whatsappStatus, setWhatsappStatus] = useState<'idle' | 'active'>('idle');

  const summary = transactions.reduce((acc, t) => {
    if (t.tipo === 'Receita') acc.income += t.valor;
    else acc.expense += t.valor;
    return acc;
  }, { income: 0, expense: 0 });

  const categoryData = transactions
    .filter(t => t.tipo === 'Despesa')
    .reduce((acc: any[], t) => {
      const existing = acc.find(item => item.name === t.categoria);
      if (existing) existing.value += t.valor;
      else acc.push({ name: t.categoria, value: t.valor });
      return acc;
    }, []);

  const barData = [
    { name: 'Receita', total: summary.income, fill: '#1ebf61' },
    { name: 'Despesa', total: summary.expense, fill: '#ef4444' }
  ];

  const formatValue = (val: number) => {
    if (hideValues) return "••••";
    return val.toLocaleString('pt-BR', { minimumFractionDigits: 2 });
  };

  const handleExportCSV = () => {
    setExcelStatus('active');
    setTimeout(() => setExcelStatus('idle'), 2000);

    const headers = ["Descrição", "Valor", "Data", "Categoria", "Tipo", "Status"];
    const rows = transactions.map(t => [t.descricao, t.valor, t.data, t.categoria, t.tipo, t.status]);
    const csvContent = "\uFEFF" + [headers, ...rows].map(e => e.join(";")).join("\n");
    const link = document.createElement("a");
    link.href = URL.createObjectURL(new Blob([csvContent], { type: 'text/csv;charset=utf-8;' }));
    link.download = `Relatorio_FinancePeres_${monthName}.csv`;
    link.click();
  };

  const handleCopyWhatsApp = () => {
    setWhatsappStatus('active');
    setTimeout(() => setWhatsappStatus('idle'), 2000);

    const incomeStr = summary.income.toLocaleString('pt-BR', { minimumFractionDigits: 2 });
    const expenseStr = summary.expense.toLocaleString('pt-BR', { minimumFractionDigits: 2 });
    const balanceStr = (summary.income - summary.expense).toLocaleString('pt-BR', { minimumFractionDigits: 2 });

    let msg = `📊 *RESUMO FINANCEIRO - ${monthName.toUpperCase()}*\n`;
    msg += `🏦 *App:* FinancePeres\n\n`;
    msg += `━━━━━━━━━━━━━━━━━━\n`;
    msg += `💰 *DADOS DO MÊS*\n`;
    msg += `━━━━━━━━━━━━━━━━━━\n`;
    msg += `🟢 *Receitas:* R$ ${incomeStr}\n`;
    msg += `🔴 *Despesas:* R$ ${expenseStr}\n`;
    msg += `💎 *Saldo Final:* R$ ${balanceStr}\n\n`;

    if (categoryData.length > 0) {
      msg += `📂 *MAIORES GASTOS POR CATEGORIA*\n`;
      categoryData.sort((a, b) => b.value - a.value).slice(0, 5).forEach(cat => {
        msg += `• ${cat.name}: R$ ${cat.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}\n`;
      });
      msg += `\n`;
    }

    msg += `━━━━━━━━━━━━━━━━━━\n`;
    msg += `✨ _Gerado por FinancePeres_`;

    navigator.clipboard.writeText(msg);
  };

  return (
    <div className="space-y-8">
      <div className="flex justify-end gap-2 mb-2">
        <button 
          onClick={handleExportCSV} 
          className={`flex items-center gap-2 px-4 py-2 border rounded-xl text-[10px] font-black uppercase tracking-wider transition-all duration-300 shadow-sm ${excelStatus === 'active' ? 'bg-emerald-500 border-emerald-500 text-white transform scale-105' : 'bg-white border-gray-200 text-slate-600 hover:bg-gray-50'}`}
        >
          {excelStatus === 'active' ? (
            <>
              <svg className="w-4 h-4 animate-bounce" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
              Baixado!
            </>
          ) : (
            <>
              <svg className="w-4 h-4 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"></path></svg>
              Exportar Excel
            </>
          )}
        </button>
        <button 
          onClick={handleCopyWhatsApp} 
          className={`flex items-center gap-2 px-4 py-2 border rounded-xl text-[10px] font-black uppercase tracking-wider transition-all duration-300 shadow-sm ${whatsappStatus === 'active' ? 'bg-emerald-500 border-emerald-500 text-white transform scale-105' : 'bg-white border-gray-200 text-slate-600 hover:bg-gray-50'}`}
        >
          {whatsappStatus === 'active' ? (
            <>
              <svg className="w-4 h-4 animate-bounce" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
              Copiado!
            </>
          ) : (
            <>
              <svg className="w-4 h-4 text-emerald-500" fill="currentColor" viewBox="0 0 24 24"><path d="M.057 24l1.687-6.163c-1.041-1.804-1.588-3.849-1.587-5.946.003-6.556 5.338-11.891 11.893-11.891 3.181.001 6.167 1.24 8.413 3.488 2.246 2.248 3.484 5.232 3.484 8.412-.003 6.557-5.338 11.892-11.893 11.892-1.997-.001-3.951-.5-5.688-1.448l-6.309 1.656zm6.29-4.143c1.589.944 3.119 1.462 4.827 1.463 5.424 0 9.835-4.411 9.838-9.835.002-2.628-1.023-5.1-2.885-6.963-1.862-1.865-4.334-2.889-6.96-2.891-5.424 0-9.835 4.411-9.838 9.836-.002 1.848.497 3.654 1.446 5.233l-.966 3.525 3.58-.938zm12.501-7.07c-.036-.06-.133-.096-.279-.169-.147-.073-.869-.43-1.003-.478-.133-.049-.231-.073-.329.073-.097.147-.378.478-.463.574-.085.096-.17.108-.317.036-.147-.073-.62-.228-1.181-.728-.436-.39-1.31-1.28-1.31-1.28.1-.036.19-.085.27-.16l.16-.16c.07-.07.12-.13.16-.2.07-.12.03-.23-.01-.31-.04-.08-.33-.79-.45-.11-.12-.3-.23-.53-.26-.14-.04-.26-.01-.35.03-.09.04-.15.24-.31.32-.08.08-.24.23-.39.43-.15.2-.23.47-.35.6-.12.13-.23.19-.39.12-.15-.07-.63-.23-1.19-.73-.44-.39-.74-.87-.82-.99-.08-.12-.01-.19.06-.27l.11-.13c.04-.05.07-.11.11-.16.03-.05.06-.12.06-.2 0-.08-.03-.17-.07-.26-.04-.09-.33-.79-.45-1.08-.12-.29-.25-.25-.33-.25h-.28c-.1 0-.26.04-.39.19-.13.15-.51.5-.51 1.21s.52 1.4 1.22 1.63c.7.23 1.21.2 1.43.17.22-.03.71-.27.81-.54.1-.27.1-.5.07-.54-.03-.04-.11-.06-.25-.14z"></path></svg>
              Relatório WhatsApp
            </>
          )}
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-white p-6 rounded-2xl border border-gray-200 shadow-sm">
          <p className="text-slate-400 text-[10px] font-bold uppercase tracking-wider">Saldo Mensal</p>
          <div className="flex items-end justify-between mt-2">
             <h3 className={`text-2xl font-black ${summary.income - summary.expense >= 0 ? 'text-slate-800' : 'text-rose-600'}`}>
               R$ {formatValue(summary.income - summary.expense)}
             </h3>
             <div className="w-10 h-10 bg-slate-50 rounded-full flex items-center justify-center text-slate-400">
               <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 10h18M7 15h1m4 0h1m-7 4h12a3 3 0 003-3V8a3 3 0 00-3-3H6a3 3 0 00-3 3v8a3 3 0 003 3z"></path></svg>
             </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-gray-200 shadow-sm">
          <p className="text-slate-400 text-[10px] font-bold uppercase tracking-wider">Receita Mensal</p>
          <div className="flex items-end justify-between mt-2">
             <h3 className="text-2xl font-black text-brand-500">
               R$ {formatValue(summary.income)}
             </h3>
             <div className="w-10 h-10 bg-brand-50 rounded-full flex items-center justify-center text-brand-500">
               <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6"></path></svg>
             </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-gray-200 shadow-sm">
          <p className="text-slate-400 text-[10px] font-bold uppercase tracking-wider">Despesa Mensal</p>
          <div className="flex items-end justify-between mt-2">
             <h3 className="text-2xl font-black text-rose-500">
               R$ {formatValue(summary.expense)}
             </h3>
             <div className="w-10 h-10 bg-rose-50 rounded-full flex items-center justify-center text-rose-500">
               <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 17h8m0 0V9m0 8l-8-8-4 4-6-6"></path></svg>
             </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-2xl border border-gray-200 shadow-sm">
          <h4 className="font-bold text-slate-800 mb-6 flex items-center gap-2">
            <span className="w-1 h-4 bg-brand-500 rounded-full"></span>
            Fluxo de Caixa
          </h4>
          <div className="h-[280px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={barData} margin={{ top: 0, right: 0, left: -20, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f3f4f6" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12, fontWeight: 600}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10}} />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', fontSize: '12px'}}
                  formatter={(value: any) => hideValues ? "••••" : `R$ ${value.toLocaleString('pt-BR')}`}
                />
                <Bar dataKey="total" radius={[6, 6, 0, 0]} barSize={40} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-gray-200 shadow-sm">
          <h4 className="font-bold text-slate-800 mb-6 flex items-center gap-2">
            <span className="w-1 h-4 bg-orange-400 rounded-full"></span>
            Gastos por Categoria
          </h4>
          <div className="h-[280px]">
            {categoryData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie data={categoryData} cx="50%" cy="45%" innerRadius={60} outerRadius={90} paddingAngle={5} dataKey="value">
                    {categoryData.map((entry, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />)}
                  </Pie>
                  <Tooltip formatter={(value: any) => hideValues ? "••••" : `R$ ${value.toLocaleString('pt-BR')}`} />
                  <Legend verticalAlign="bottom" wrapperStyle={{fontSize: '11px', fontWeight: 600, color: '#64748b'}} />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="flex flex-col items-center justify-center h-full text-slate-300">
                <svg className="w-12 h-12 mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9.172 16.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                <p className="text-sm font-medium">Sem despesas registradas</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Transaction, TransactionType, TransactionStatus, TransactionFrequency, CATEGORIES } from '../types';

interface Props {
  transactions: Transaction[];
  onAdd: (t: Omit<Transaction, 'id'>) => void;
  onUpdate: (t: Transaction) => void;
  onDelete: (id: string) => void;
  onToggleStatus: (id: string) => void;
  onCopyPrevious: () => void;
  defaultMonth: number;
  defaultYear: number;
  monthName: string;
  hideValues: boolean;
}

const TransactionList: React.FC<Props> = ({ transactions, onAdd, onUpdate, onDelete, onToggleStatus, onCopyPrevious, defaultMonth, defaultYear, monthName, hideValues }) => {
  const [showModal, setShowModal] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [copyStatus, setCopyStatus] = useState<'idle' | 'active'>('idle');

  const getDefaultDate = () => {
    const now = new Date();
    return new Date(defaultYear, defaultMonth, now.getDate()).toISOString().split('T')[0];
  };

  const initialFormState = {
    descricao: '', valor: '', data: getDefaultDate(), categoria: 'Outro', tipo: 'Despesa' as TransactionType, status: 'Pendente' as TransactionStatus, frequencia: 'Fixo' as TransactionFrequency
  };

  const [formData, setFormData] = useState(initialFormState);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.descricao || !formData.valor) return;
    const payload = { ...formData, valor: parseFloat(formData.valor) };
    if (editingTransaction) onUpdate({ ...payload, id: editingTransaction.id });
    else onAdd(payload);
    setShowModal(false);
  };

  const handleCopy = () => {
    setCopyStatus('active');
    setTimeout(() => setCopyStatus('idle'), 2000);
    onCopyPrevious();
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-wrap items-center justify-between gap-4 bg-white p-4 rounded-2xl border border-gray-200 shadow-sm">
        <div className="flex gap-2">
          <button 
            onClick={handleCopy} 
            className={`px-4 py-2 rounded-xl text-xs font-black uppercase tracking-wider transition-all duration-300 border ${copyStatus === 'active' ? 'bg-emerald-500 border-emerald-500 text-white transform scale-105' : 'bg-gray-50 text-slate-600 border-gray-100 hover:bg-gray-100'}`}
          >
            {copyStatus === 'active' ? 'Copiado!' : 'Importar Anterior'}
          </button>
        </div>

        <div className="flex gap-2">
          <button onClick={() => { setEditingTransaction(null); setFormData(initialFormState); setShowModal(true); }} className="px-6 py-2 bg-brand-500 text-white rounded-xl text-sm font-extrabold shadow-lg shadow-brand-100 hover:bg-brand-600 transition active:scale-95">
             + Novo Lançamento
          </button>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-gray-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left whitespace-nowrap">
            <thead className="bg-gray-50/50 text-[10px] uppercase font-bold text-slate-400">
              <tr>
                <th className="px-6 py-4">Status</th>
                <th className="px-6 py-4">Lançamento</th>
                <th className="px-6 py-4">Categoria</th>
                <th className="px-6 py-4">Valor</th>
                <th className="px-6 py-4 text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {transactions.length > 0 ? transactions.map(t => (
                <tr key={t.id} className="hover:bg-gray-50/50 transition">
                  <td className="px-6 py-4">
                    <button onClick={() => onToggleStatus(t.id)} className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-wider ${t.status === 'Pago' ? 'bg-brand-50 text-brand-600' : 'bg-orange-50 text-orange-600'}`}>
                      {t.status}
                    </button>
                  </td>
                  <td className="px-6 py-4">
                    <div className="font-bold text-slate-800 text-sm">{t.descricao}</div>
                    <div className="text-[10px] text-slate-400 font-medium">{t.data} • #{t.id}</div>
                  </td>
                  <td className="px-6 py-4 text-xs font-bold text-slate-500">{t.categoria}</td>
                  <td className={`px-6 py-4 font-black text-sm ${t.tipo === 'Receita' ? 'text-brand-500' : 'text-rose-500'}`}>
                    {hideValues ? "R$ ••••" : `R$ ${t.valor.toLocaleString('pt-BR', {minimumFractionDigits:2})}`}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button onClick={() => { setEditingTransaction(t); setFormData({descricao:t.descricao, valor:t.valor.toString(), data:t.data, categoria:t.categoria, tipo:t.tipo, status:t.status, frequencia:t.frequencia}); setShowModal(true); }} className="p-2 text-slate-300 hover:text-brand-500 transition">
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z"></path></svg>
                    </button>
                    <button onClick={() => onDelete(t.id)} className="p-2 text-slate-300 hover:text-rose-500 transition ml-1">
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                    </button>
                  </td>
