import React, { useState } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  PieChart, Pie, Cell, Legend 
} from 'recharts';
import { Transaction } from '../types.ts';

interface Props {
  transactions: Transaction[];
  hideValues: boolean;
  monthName: string;
}

const COLORS = ['#1ebf61', '#34d399', '#f59e0b', '#ef4444', '#10b981', '#f97316', '#06b6d4', '#8b5cf6'];

const Dashboard: React.FC<Props> = ({ transactions, hideValues, monthName }) => {
  const [excelStatus, setExcelStatus] = useState<'idle' | 'success'>('idle');
  const [whatsappStatus, setWhatsappStatus] = useState<'idle' | 'success'>('idle');

  const summary = transactions.reduce((acc, t) => {
    if (t.tipo === 'Receita') acc.income += t.valor;
    else acc.expense += t.valor;
    return acc;
  }, { income: 0, expense: 0 });

  const categoryData = transactions
    .filter(t => t.tipo === 'Despesa')
    .reduce((acc: any[], t) => {
      const existing = acc.find(item => item.name === t.categoria);
      if (existing) existing.value += t.valor;
      else acc.push({ name: t.categoria, value: t.valor });
      return acc;
    }, []);

  const formatValue = (val: number) => {
    if (hideValues) return "••••";
    return val.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  };

  const handleExport = () => {
    setExcelStatus('success');
    const headers = "Descrição;Valor;Data;Categoria;Tipo\n";
    const body = transactions.map(t => `${t.descricao};${t.valor};${t.data};${t.categoria};${t.tipo}`).join("\n");
    const blob = new Blob(["\uFEFF" + headers + body], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = `finance_report_${monthName}.csv`;
    link.click();
    setTimeout(() => setExcelStatus('idle'), 2000);
  };

  const handleWhatsApp = () => {
    setWhatsappStatus('success');
    let msg = `📊 *Resumo Financeiro - ${monthName}*\n\n`;
    msg += `✅ Receitas: ${formatValue(summary.income)}\n`;
    msg += `🔴 Despesas: ${formatValue(summary.expense)}\n`;
    msg += `💎 Saldo: ${formatValue(summary.income - summary.expense)}\n\n`;
    msg += `✨ Gerado via FinancePeres`;
    navigator.clipboard.writeText(msg);
    setTimeout(() => setWhatsappStatus('idle'), 2000);
  };

  return (
    <div className="space-y-8 animate-enter">
      <div className="flex justify-end gap-3">
        <button onClick={handleExport} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-wider transition-all border ${excelStatus === 'success' ? 'bg-emerald-500 border-emerald-500 text-white transform scale-105' : 'bg-white border-slate-100 text-slate-500 hover:bg-slate-50'}`}>
          {excelStatus === 'success' ? '✓ Exportado' : 'Exportar Excel'}
        </button>
        <button onClick={handleWhatsApp} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-wider transition-all border ${whatsappStatus === 'success' ? 'bg-emerald-500 border-emerald-500 text-white transform scale-105' : 'bg-white border-slate-100 text-slate-500 hover:bg-slate-50'}`}>
          {whatsappStatus === 'success' ? '✓ Copiado' : 'Relatório WhatsApp'}
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-50">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Total Balanço</p>
          <h3 className={`text-2xl font-black ${summary.income - summary.expense >= 0 ? 'text-slate-800' : 'text-rose-500'}`}>
            {formatValue(summary.income - summary.expense)}
          </h3>
        </div>
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-50">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Total Receitas</p>
          <h3 className="text-2xl font-black text-brand-500">{formatValue(summary.income)}</h3>
        </div>
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-50">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Total Despesas</p>
          <h3 className="text-2xl font-black text-rose-500">{formatValue(summary.expense)}</h3>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-50 min-h-[400px]">
          <h4 className="font-black text-slate-800 mb-8 uppercase text-xs tracking-widest">Fluxo de Caixa</h4>
          <ResponsiveContainer width="100%" height={300}>
            <BarChart data={[{ name: 'Receita', val: summary.income, fill: '#1ebf61' }, { name: 'Despesa', val: summary.expense, fill: '#ef4444' }]}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 11, fontWeight: 700 }} />
              <YAxis hide />
              <Tooltip cursor={{ fill: '#f8fafc' }} />
              <Bar dataKey="val" radius={[8, 8, 0, 0]} barSize={60} />
            </BarChart>
          </ResponsiveContainer>
        </div>

        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-50 min-h-[400px]">
          <h4 className="font-black text-slate-800 mb-8 uppercase text-xs tracking-widest">Gastos por Categoria</h4>
          <ResponsiveContainer width="100%" height={300}>
            <PieChart>
              <Pie data={categoryData} cx="50%" cy="50%" innerRadius={60} outerRadius={90} paddingAngle={5} dataKey="value">
                {categoryData.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
              </Pie>
              <Tooltip />
              <Legend verticalAlign="bottom" wrapperStyle={{ fontSize: 10, fontWeight: 700 }} />
            </PieChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Transaction, CATEGORIES } from '../types.ts';

interface Props {
  transactions: Transaction[];
  onAdd: (t: Omit<Transaction, 'id'>) => void;
  onUpdate: (t: Transaction) => void;
  onDelete: (id: string) => void;
  onToggleStatus: (id: string) => void;
  onCopyPrevious: () => void;
  defaultMonth: number;
  defaultYear: number;
  monthName: string;
  hideValues: boolean;
}

const TransactionList: React.FC<Props> = ({ transactions, onAdd, onUpdate, onDelete, onToggleStatus, onCopyPrevious, defaultMonth, defaultYear, hideValues }) => {
  const [showModal, setShowModal] = useState(false);
  const [saveStatus, setSaveStatus] = useState<'idle' | 'success'>('idle');
  const [importStatus, setImportStatus] = useState<'idle' | 'success'>('idle');

  const [formData, setFormData] = useState({
    descricao: '', valor: '', data: new Date(defaultYear, defaultMonth, 1).toISOString().split('T')[0], categoria: 'Outro', tipo: 'Despesa' as 'Receita' | 'Despesa', status: 'Pendente' as 'Pago' | 'Pendente'
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setSaveStatus('success');
    onAdd({ ...formData, valor: parseFloat(formData.valor), frequencia: 'Esporádico' });
    setTimeout(() => {
      setShowModal(false);
      setSaveStatus('idle');
      setFormData({ ...formData, descricao: '', valor: '' });
    }, 1500);
  };

  const handleImport = () => {
    setImportStatus('success');
    onCopyPrevious();
    setTimeout(() => setImportStatus('idle'), 2000);
  };

  return (
    <div className="space-y-6 animate-enter">
      <div className="flex justify-between items-center bg-white p-6 rounded-3xl border border-slate-50 shadow-sm">
        <button onClick={handleImport} className={`px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all border ${importStatus === 'success' ? 'bg-emerald-500 border-emerald-500 text-white' : 'bg-slate-50 border-slate-100 text-slate-500'}`}>
          {importStatus === 'success' ? '✓ Importado' : 'Importar Anterior'}
        </button>
        <button onClick={() => setShowModal(true)} className="px-8 py-3 bg-brand-500 text-white rounded-2xl text-xs font-black uppercase tracking-widest shadow-xl shadow-brand-100 hover:bg-brand-600 transition-all">
          + Novo Lançamento
        </button>
      </div>

      <div className="bg-white rounded-[2rem] border border-slate-50 shadow-sm overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50/50 text-[10px] uppercase font-black text-slate-400">
            <tr>
              <th className="px-8 py-6">Status</th>
              <th className="px-8 py-6">Descrição</th>
              <th className="px-8 py-6">Categoria</th>
              <th className="px-8 py-6">Valor</th>
              <th className="px-8 py-6 text-right">Ação</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {transactions.map(t => (
              <tr key={t.id} className="hover:bg-slate-50/30 transition-colors">
                <td className="px-8 py-5">
                  <button onClick={() => onToggleStatus(t.id)} className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest ${t.status === 'Pago' ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'}`}>
                    {t.status}
                  </button>
                </td>
                <td className="px-8 py-5">
                  <p className="font-bold text-slate-800 text-sm">{t.descricao}</p>
                  <p className="text-[10px] text-slate-400 font-bold uppercase mt-0.5">{t.data}</p>
                </td>
                <td className="px-8 py-5 text-[10px] font-black text-slate-500 uppercase">{t.categoria}</td>
                <td className={`px-8 py-5 font-black text-sm ${t.tipo === 'Receita' ? 'text-brand-500' : 'text-rose-500'}`}>
                  {hideValues ? 'R$ ••••' : t.valor.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                </td>
                <td className="px-8 py-5 text-right">
                  <button onClick={() => onDelete(t.id)} className="p-2 text-slate-300 hover:text-rose-500 transition-colors">
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {showModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md flex items-center justify-center z-[100] p-4">
          <form onSubmit={handleSubmit} className="bg-white rounded-[3rem] w-full max-w-md p-10 space-y-6 shadow-2xl animate-enter">
            <h3 className="text-2xl font-black text-slate-800 tracking-tight">Novo Lançamento</h3>

            <div className="flex p-2 bg-slate-50 rounded-2xl">
              <button type="button" onClick={() => setFormData({...formData, tipo: 'Despesa'})} className={`flex-1 py-3 rounded-xl text-[10px] font-black transition-all ${formData.tipo === 'Despesa' ? 'bg-white text-rose-500 shadow-sm' : 'text-slate-400'}`}>DESPESA</button>
              <button type="button" onClick={() => setFormData({...formData, tipo: 'Receita'})} className={`flex-1 py-3 rounded-xl text-[10px] font-black transition-all ${formData.tipo === 'Receita' ? 'bg-white text-brand-600 shadow-sm' : 'text-slate-400'}`}>RECEITA</button>
            </div>

            <div className="space-y-4">
              <input type="text" value={formData.descricao} onChange={e => setFormData({...formData, descricao: e.target.value})} placeholder="Descrição" required className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl focus:border-brand-500 focus:bg-white outline-none font-bold text-slate-800 transition-all" />
              <input type="number" step="0.01" value={formData.valor} onChange={e => setFormData({...formData, valor: e.target.value})} placeholder="0,00" required className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl focus:border-brand-500 focus:bg-white outline-none font-black text-3xl text-slate-800" />
              <div className="grid grid-cols-2 gap-4">
                <input type="date" value={formData.data} onChange={e => setFormData({...formData, data: e.target.value})} className="p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none text-xs font-black text-slate-600" />
                <select value={formData.categoria} onChange={e => setFormData({...formData, categoria: e.target.value})} className="p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none text-xs font-black text-slate-600">
                  {(formData.tipo === 'Receita' ? CATEGORIES.INCOME : CATEGORIES.EXPENSE).map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
            </div>

            <div className="flex gap-4 pt-4">
              <button type="button" onClick={() => setShowModal(false)} className="flex-1 p-5 bg-slate-50 text-slate-400 rounded-2xl font-black text-[11px] uppercase tracking-widest hover:bg-slate-100 transition-all">Fechar</button>
              <button type="submit" className={`flex-1 p-5 text-white rounded-2xl font-black text-[11px] uppercase tracking-widest shadow-xl transition-all ${saveStatus === 'success' ? 'bg-emerald-500' : (formData.tipo === 'Receita' ? 'bg-brand-500' : 'bg-rose-500')}`}>
                {saveStatus === 'success' ? 'Salvo!' : 'Confirmar'}
              </button>
            </div>
          </form>
        </div>
      )}
    </div>
  );
};

export default TransactionList;

export type TransactionType = 'Receita' | 'Despesa';
export type TransactionStatus = 'Pago' | 'Pendente';
export type TransactionFrequency = 'Fixo' | 'Esporádico';

export interface Transaction {
  id: string;
  descricao: string;
  valor: number;
  data: string; // Formato ISO yyyy-mm-dd
  categoria: string;
  tipo: TransactionType;
  status: TransactionStatus;
  frequencia: TransactionFrequency;
}

export interface MonthlyData {
  month: number;
  year: number;
  transactions: Transaction[];
}

export const CATEGORIES = {
  INCOME: ['Salário', 'Freelance', 'Investimento', 'Presente', 'Outro'],
  EXPENSE: ['Moradia', 'Alimentação', 'Transporte', 'Utilidades', 'Lazer', 'Saúde', 'Educação', 'Compras', 'Outro']
};

import React, { useState, useEffect, useMemo } from 'react';
import { Transaction } from './types.ts';
import Dashboard from './components/Dashboard.tsx';
import TransactionList from './components/TransactionList.tsx';
import { sheetsService } from './services/googleSheetsService.ts';

const App: React.FC = () => {
  const [isHome, setIsHome] = useState(true);
  const [hideValues, setHideValues] = useState(true);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'transactions'>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [syncStatus, setSyncStatus] = useState<'online' | 'offline' | 'syncing'>('syncing');

  const [selectedMonth, setSelectedMonth] = useState(new Date().getMonth());
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());

  const loadData = async () => {
    setSyncStatus('syncing');
    try {
      const data = await sheetsService.getAll();
      setTransactions(data || []);
      localStorage.setItem('ff_transactions', JSON.stringify(data || []));
      setSyncStatus('online');
    } catch (error) {
      console.error("Sync error:", error);
      const saved = localStorage.getItem('ff_transactions');
      if (saved) setTransactions(JSON.parse(saved));
      setSyncStatus('offline');
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const monthNames = ["Janeiro", "Fevereiro", "Março", "Abril", "Maio", "Junho", "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"];

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const d = new Date(t.data);
      return d.getMonth() === selectedMonth && d.getFullYear() === selectedYear;
    });
  }, [transactions, selectedMonth, selectedYear]);

  const addTransaction = async (t: Omit<Transaction, 'id'>) => {
    setSyncStatus('syncing');
    const newTransaction = { ...t, id: Math.random().toString(36).substr(2, 9) } as Transaction;
    const newList = [...transactions, newTransaction];
    setTransactions(newList);
    const success = await sheetsService.save(newTransaction);
    setSyncStatus(success ? 'online' : 'offline');
  };

  const updateTransaction = async (updated: Transaction) => {
    setSyncStatus('syncing');
    const newList = transactions.map(t => t.id === updated.id ? updated : t);
    setTransactions(newList);
    const success = await sheetsService.save(updated);
    setSyncStatus(success ? 'online' : 'offline');
  };

  const deleteTransaction = async (id: string) => {
    setSyncStatus('syncing');
    const newList = transactions.filter(t => t.id !== id);
    setTransactions(newList);
    const success = await sheetsService.delete(id);
    setSyncStatus(success ? 'online' : 'offline');
  };

  if (isHome) {
    return (
      <div className="min-h-screen bg-white flex flex-col items-center justify-center p-6 text-center animate-enter">
        <div className="w-20 h-20 bg-brand-500 rounded-[2rem] flex items-center justify-center mb-8 shadow-2xl shadow-brand-200">
          <svg className="w-10 h-10 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
        </div>
        <h1 className="text-4xl font-black text-slate-800 mb-2 tracking-tight">Finance<span className="text-brand-500">Peres</span></h1>
        <p className="text-slate-400 max-w-sm mb-12 font-medium">Controle total da sua vida financeira de forma simples e direta.</p>
        <button onClick={() => setIsHome(false)} className="w-full max-w-xs py-5 bg-brand-500 text-white rounded-2xl font-black text-lg shadow-xl hover:bg-brand-600 transition-all active:scale-95">Entrar no App</button>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      {/* Sidebar */}
      <aside className="w-full md:w-72 bg-white border-r border-slate-100 flex flex-col sticky top-0 md:h-screen z-20">
        <div className="p-8">
          <div className="flex items-center gap-3 mb-10">
            <div className="w-9 h-9 bg-brand-500 rounded-xl flex items-center justify-center text-white font-black">FP</div>
            <h1 className="text-xl font-black tracking-tight text-slate-800">Finance<span className="text-brand-500">Peres</span></h1>
          </div>

          {/* Status de Sincronização */}
          <div className={`flex items-center gap-3 p-4 rounded-2xl border transition-all mb-8 ${syncStatus === 'online' ? 'bg-emerald-50 border-emerald-100' : syncStatus === 'syncing' ? 'bg-amber-50 border-amber-100' : 'bg-rose-50 border-rose-100'}`}>
            <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${syncStatus === 'online' ? 'bg-emerald-500' : syncStatus === 'syncing' ? 'bg-amber-500 animate-pulse' : 'bg-rose-500'} text-white`}>
              {syncStatus === 'online' ? (
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M5 13l4 4L19 7"></path></svg>
              ) : syncStatus === 'syncing' ? (
                <svg className="w-5 h-5 animate-spin" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path></svg>
              ) : (
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"></path></svg>
              )}
            </div>
            <div>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Planilha</p>
              <p className={`text-xs font-black uppercase tracking-tight ${syncStatus === 'online' ? 'text-emerald-600' : syncStatus === 'syncing' ? 'text-amber-600' : 'text-rose-600'}`}>
                {syncStatus === 'online' ? 'Sincronizado' : syncStatus === 'syncing' ? 'Sincronizando' : 'Modo Offline'}
              </p>
            </div>
          </div>

          <nav className="space-y-1">
            <button onClick={() => setActiveTab('dashboard')} className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-xl font-bold text-sm transition-all ${activeTab === 'dashboard' ? 'bg-brand-500 text-white shadow-lg shadow-brand-100' : 'text-slate-400 hover:bg-slate-50'}`}>
               <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 3.055A9.001 9.001 0 1020.945 13H11V3.055z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M20.488 9H15V3.512A9.025 9.025 0 0120.488 9z"></path></svg>
               Dashboard
            </button>
            <button onClick={() => setActiveTab('transactions')} className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-xl font-bold text-sm transition-all ${activeTab === 'transactions' ? 'bg-brand-500 text-white shadow-lg shadow-brand-100' : 'text-slate-400 hover:bg-slate-50'}`}>
               <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01"></path></svg>
               Lançamentos
            </button>
          </nav>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-6 md:p-12 overflow-y-auto max-h-screen">
        <header className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-4">
          <div>
            <h2 className="text-3xl font-black text-slate-800">{activeTab === 'dashboard' ? 'Dashboard' : 'Lançamentos'}</h2>
            <div className="flex items-center gap-2 mt-2">
              <span className="text-xs font-black text-brand-500 uppercase bg-brand-50 px-2 py-0.5 rounded-md">{monthNames[selectedMonth]}</span>
              <span className="text-xs font-black text-slate-300 uppercase">{selectedYear}</span>
            </div>
          </div>

          <div className="flex gap-2">
            <select value={selectedMonth} onChange={(e) => setSelectedMonth(parseInt(e.target.value))} className="bg-white border border-slate-100 rounded-xl px-4 py-2 text-xs font-bold outline-none shadow-sm">
              {monthNames.map((name, i) => <option key={i} value={i}>{name}</option>)}
            </select>
            <button onClick={() => setHideValues(!hideValues)} className="p-2.5 bg-white border border-slate-100 rounded-xl text-slate-400 hover:text-brand-500 transition-all shadow-sm">
              {hideValues ? (
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l3.59 3.59m0 0A9.953 9.953 0 0112 5c4.478 0 8.268-2.943 9.543 7a10.025 10.025 0 01-4.132 5.411m0 0L21 21"></path></svg>
              ) : (
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268-2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z"></path></svg>
              )}
            </button>
          </div>
        </header>

        {activeTab === 'dashboard' ? (
          <Dashboard transactions={filteredTransactions} hideValues={hideValues} monthName={monthNames[selectedMonth]} />
        ) : (
          <TransactionList 
            transactions={filteredTransactions} 
            onAdd={addTransaction} 
            onUpdate={updateTransaction} 
            onDelete={deleteTransaction} 
            onToggleStatus={(id) => {
