### Código do Google Apps Script (Cole no Editor de Scripts da sua Planilha)

Siga estes passos:
1. Abra sua planilha do Google.
2. Vá em **Extensões** > **Apps Script**.
3. Apague todo o código existente e cole o código abaixo.
4. Clique em **Implantar** > **Nova Implantação**.
5. Selecione **App da Web**.
6. Em "Quem pode acessar", selecione **Qualquer pessoa**.
7. Copie a URL gerada e cole no seu arquivo `services/googleSheetsService.ts` no lugar da `API_URL`.

```javascript
/**
 * Google Apps Script para FinancePeres
 * Este script gerencia a leitura e escrita de dados na planilha.
 */

function doGet() {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();
  const data = sheet.getDataRange().getValues();
  const headers = data[0];
  const rows = data.slice(1);

  const result = rows.map(row => {
    let obj = {};
    headers.forEach((header, i) => {
      obj[header] = row[i];
    });
    return obj;
  });

  return ContentService.createTextOutput(JSON.stringify(result))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  try {
    const sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();
    const requestData = JSON.parse(e.postData.contents);
    const action = requestData.action;
    const payload = requestData.payload;

    // Lista de cabeçalhos padrão
    const headers = ["id", "descricao", "valor", "data", "categoria", "tipo", "status", "frequencia"];

    // Garantir que a planilha tenha cabeçalhos se estiver vazia
    if (sheet.getLastRow() === 0) {
      sheet.appendRow(headers);
    }

    if (action === "save") {
      const data = sheet.getDataRange().getValues();
      let foundRow = -1;

      // Procurar por ID existente para atualizar
      for (let i = 1; i < data.length; i++) {
        if (data[i][0] == payload.id) {
          foundRow = i + 1;
          break;
        }
      }

      const newRow = headers.map(header => payload[header] !== undefined ? payload[header] : "");

      if (foundRow !== -1) {
        sheet.getRange(foundRow, 1, 1, newRow.length).setValues([newRow]);
      } else {
        sheet.appendRow(newRow);
      }
    } 
    else if (action === "delete") {
      const data = sheet.getDataRange().getValues();
      for (let i = 1; i < data.length; i++) {
        if (data[i][0] == payload.id) {
          sheet.deleteRow(i + 1);
          break;
        }
      }
    } 
    else if (action === "syncAll") {
      sheet.clear();
      sheet.appendRow(headers);
      if (Array.isArray(payload)) {
        payload.forEach(item => {
          const row = headers.map(h => item[h] !== undefined ? item[h] : "");
          sheet.appendRow(row);
        });
      }
    }

    return ContentService.createTextOutput(JSON.stringify({status: "success"}))
      .setMimeType(ContentService.MimeType.JSON);

  } catch (error) {
    return ContentService.createTextOutput(JSON.stringify({status: "error", message: error.toString()}))
      .setMimeType(ContentService.MimeType.JSON);
  }
}
```

**Por que esse erro estava acontecendo?**
O erro de compilação no Vercel que você enviou anteriormente era causado pelo fato de o projeto estar tentando usar o **React 19** via `importmap` no HTML, enquanto as bibliotecas (como `recharts`) e o `package.json` pediam o **React 18**. Ao unificar tudo para a versão 18.2.0 estável e remover o `importmap` manual, o Vite consegue gerenciar o build de forma limpa, resolvendo o conflito de "peer dependencies".

