Para resolver definitivamente o problema de sincronização, precisamos garantir que o **Google Apps Script (GAS)** esteja configurado corretamente para receber e processar os dados e que o **App** esteja enviando as informações no formato que o Google espera.

Abaixo, apresento primeiro o código que você deve colar no seu **Editor de Script da Planilha Google** e, em seguida, as correções no código do seu aplicativo.

### 1. Código para o Google Apps Script (Copie e cole na sua Planilha)

No Google Sheets: `Extensões` > `Apps Script`. Apague tudo e cole:

```javascript
/**
 * Script para gerenciar FinancePeres
 * Colunas esperadas na Planilha: id, descricao, valor, data, categoria, tipo, status, frequencia
 */

function doGet() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheets()[0];
  const data = sheet.getDataRange().getValues();
  const headers = data[0];
  const rows = data.slice(1);

  const result = rows.map(row => {
    let obj = {};
    headers.forEach((header, i) => {
      obj[header] = row[i];
    });
    return obj;
  });

  return ContentService.createTextOutput(JSON.stringify(result))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheets()[0];
  const body = JSON.parse(e.postData.contents);
  const action = body.action;
  const payload = body.payload;

  if (action === 'save') {
    saveTransaction(sheet, payload);
  } else if (action === 'delete') {
    deleteTransaction(sheet, payload.id);
  } else if (action === 'syncAll') {
    syncAllTransactions(sheet, payload);
  }

  return ContentService.createTextOutput(JSON.stringify({status: 'success'}))
    .setMimeType(ContentService.MimeType.JSON);
}

function saveTransaction(sheet, transaction) {
  const data = sheet.getDataRange().getValues();
  const headers = data[0];
  const idIndex = headers.indexOf('id');

  let rowIndex = -1;
  for (let i = 1; i < data.length; i++) {
    if (data[i][idIndex] == transaction.id) {
      rowIndex = i + 1;
      break;
    }
  }

  const rowValues = headers.map(header => transaction[header] || "");

  if (rowIndex > -1) {
    sheet.getRange(rowIndex, 1, 1, headers.length).setValues([rowValues]);
  } else {
    sheet.appendRow(rowValues);
  }
}

function deleteTransaction(sheet, id) {
  const data = sheet.getDataRange().getValues();
  const headers = data[0];
  const idIndex = headers.indexOf('id');

  for (let i = 1; i < data.length; i++) {
    if (data[i][idIndex] == id) {
      sheet.deleteRow(i + 1);
      break;
    }
  }
}

function syncAllTransactions(sheet, transactions) {
  const headers = ['id', 'descricao', 'valor', 'data', 'categoria', 'tipo', 'status', 'frequencia'];
  sheet.clear();
  sheet.appendRow(headers);

  if (transactions && transactions.length > 0) {
    const values = transactions.map(t => headers.map(h => t[h] || ""));
    sheet.getRange(2, 1, values.length, headers.length).setValues(values);
  }
}
```
**Importante:** Após salvar, clique em **Implantar** > **Nova Implantação** > Tipo: **App da Web** > Executar como: **Eu** > Quem pode acessar: **Qualquer pessoa**. Copie a nova URL gerada.

