import { Transaction } from "../types";

/**
 * URL da nova planilha do Google Sheets utilizada como banco de dados.
 * IMPORTANTE: Para evitar o erro 'Failed to fetch', o script do Google Apps Script DEVE:
 * 1. Ser implantado como 'App da Web' (Web App).
 * 2. Configurado para 'Executar como: Eu' (Execute as: Me).
 * 3. Configurado para 'Quem tem acesso: Qualquer pessoa' (Who has access: Anyone).
 * Se o acesso estiver como 'Qualquer pessoa com conta Google', o fetch falhará por causa do redirecionamento de login.
 */
const API_URL = "https://script.google.com/macros/s/AKfycbw4nTmrm93u1O83PElDyuLLMNRcOeiZuGMD-5joI5S9b5mO9oRfeHnIZ3t3HrlMqc5lSQ/exec";

export const sheetsService = {
  async getAll(): Promise<Transaction[]> {
    if (!API_URL) return [];
    try {
      // O Google Apps Script redireciona a requisição (302). 
      // Usamos a forma mais simples de fetch para evitar disparar verificações complexas de CORS que o Google não suporta bem no redirect.
      const response = await fetch(API_URL, {
        method: "GET",
        redirect: "follow"
      });

      if (!response.ok) {
        throw new Error(`Erro na rede: ${response.status} ${response.statusText}`);
      }

      const data = await response.json();

      if (!Array.isArray(data)) {
        console.warn("Dados recebidos não são uma lista válida.");
        return [];
      }

      return data.map((t: any) => ({
        ...t,
        id: t.id ? t.id.toString() : Math.random().toString(36).substr(2, 9),
        valor: typeof t.valor === 'string' ? parseFloat(t.valor.replace(',', '.')) : (parseFloat(t.valor) || 0),
        data: t.data ? t.data.toString().split('T')[0] : new Date().toISOString().split('T')[0],
        tipo: t.tipo || 'Despesa',
        status: t.status || 'Pendente',
        categoria: t.categoria || 'Outro',
        frequencia: t.frequencia || 'Esporádico'
      }));
    } catch (error) {
      console.error("Erro detalhado ao carregar do Google Sheets:", error);

      // Fallback para dados locais em caso de falha de conexão
      const localData = localStorage.getItem('ff_transactions');
      if (localData) {
        try {
          return JSON.parse(localData);
        } catch {
          return [];
        }
      }
      return [];
    }
  },

  async save(transaction: Transaction): Promise<boolean> {
    if (!API_URL) return false;
    try {
      // Para POST no Google Apps Script, 'no-cors' é a abordagem mais estável.
      // Isso envia o dado com sucesso sem exigir headers complexos que o Google pode barrar.
      await fetch(API_URL, {
        method: "POST",
        mode: "no-cors", 
        headers: { "Content-Type": "text/plain" },
        body: JSON.stringify({ action: "save", payload: transaction })
      });
      return true; 
    } catch (error) {
      console.error("Erro ao salvar:", error);
      return false;
    }
  },

  async delete(id: string): Promise<boolean> {
    if (!API_URL) return false;
    try {
      await fetch(API_URL, {
        method: "POST",
        mode: "no-cors",
        headers: { "Content-Type": "text/plain" },
        body: JSON.stringify({ action: "delete", payload: { id } })
      });
      return true;
    } catch (error) {
      console.error("Erro ao deletar:", error);
      return false;
    }
  },

  async syncAll(transactions: Transaction[]): Promise<boolean> {
    if (!API_URL) return false;
    try {
      await fetch(API_URL, {
        method: "POST",
        mode: "no-cors",
        headers: { "Content-Type": "text/plain" },
        body: JSON.stringify({ action: "syncAll", payload: transactions })
      });
      return true;
    } catch (error) {
      console.error("Erro ao sincronizar:", error);
      return false;
    }
  }
};

import React, { useState, useEffect } from 'react';
import { Transaction, CATEGORIES, TransactionFrequency } from '../types.ts';

interface Props {
  transactions: Transaction[];
  onAdd: (t: Omit<Transaction, 'id'>) => void;
  onUpdate: (t: Transaction) => void;
  onDelete: (id: string) => void;
  onToggleStatus: (id: string) => void;
  onCopyPrevious: () => void;
  defaultMonth: number;
  defaultYear: number;
  monthName: string;
  hideValues: boolean;
}

const TransactionList: React.FC<Props> = ({ 
  transactions, 
  onAdd, 
  onUpdate, 
  onDelete, 
  onToggleStatus, 
  onCopyPrevious, 
  defaultMonth, 
  defaultYear, 
  hideValues 
}) => {
  const [showModal, setShowModal] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [saveStatus, setSaveStatus] = useState<'idle' | 'success'>('idle');
  const [importStatus, setImportStatus] = useState<'idle' | 'success'>('idle');

  // Filtra apenas receitas e despesas para esta aba
  const displayTransactions = transactions.filter(t => t.tipo !== 'Investimento');

  const getInitialDate = () => {
    const month = (defaultMonth + 1).toString().padStart(2, '0');
    return `${defaultYear}-${month}-01`;
  };

  const [formData, setFormData] = useState({
    descricao: '', 
    valor: '', 
    data: getInitialDate(), 
    categoria: 'Outro', 
    tipo: 'Despesa' as 'Receita' | 'Despesa', 
    status: 'Pendente' as 'Pago' | 'Pendente',
    frequencia: 'Esporádico' as TransactionFrequency
  });

  useEffect(() => {
    if (editingTransaction) {
      setFormData({
        descricao: editingTransaction.descricao,
        valor: editingTransaction.valor.toString(),
        data: editingTransaction.data,
        categoria: editingTransaction.categoria,
        tipo: editingTransaction.tipo as any,
        status: editingTransaction.status,
        frequencia: editingTransaction.frequencia || 'Esporádico'
      });
    } else {
      setFormData({
        descricao: '', 
        valor: '', 
        data: getInitialDate(), 
        categoria: 'Outro', 
        tipo: 'Despesa', 
        status: 'Pendente',
        frequencia: 'Esporádico'
      });
    }
  }, [editingTransaction, showModal, defaultMonth, defaultYear]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setSaveStatus('success');

    const transactionData = {
      ...formData,
      valor: parseFloat(formData.valor),
    };

    if (editingTransaction) {
      onUpdate({ ...transactionData, id: editingTransaction.id } as Transaction);
    } else {
      onAdd(transactionData);
    }

    setTimeout(() => {
      setShowModal(false);
      setEditingTransaction(null);
      setSaveStatus('idle');
    }, 1000);
  };

  const handleEdit = (t: Transaction) => {
    setEditingTransaction(t);
    setShowModal(true);
  };

  const handleImport = () => {
    setImportStatus('success');
    onCopyPrevious();
    setTimeout(() => setImportStatus('idle'), 2000);
  };

  const closeModal = () => {
    setShowModal(false);
    setEditingTransaction(null);
  };

  const formatDateDisplay = (dateStr: string) => {
    if (!dateStr) return "-";
    const [y, m, d] = dateStr.split('-');
    return `${d}/${m}/${y}`;
