Para que a sincronização funcione corretamente entre o seu App e o Google Sheets, você deve seguir estes passos exatamente:

### 1. Preparação da Planilha
1. Crie uma nova Planilha Google.
2. Nomeie a primeira aba (página) como **`Transacoes`**.
3. Na primeira linha (cabeçalhos), preencha exatamente nesta ordem nas colunas A até H:
   - **ID** | **Descrição** | **Valor** | **Data** | **Categoria** | **Tipo** | **Status** | **Frequência**

---

### 2. O Código do App Script
1. Na planilha, vá em **Extensões** > **App Script**.
2. Apague qualquer código que esteja lá e cole este:

```javascript
/**
 * FINANCE PERES - BACKEND SCRIPT
 * Este script gerencia as transações enviadas pelo Web App.
 */

const SHEET_NAME = 'Transacoes';
const HEADERS = ['id', 'descricao', 'valor', 'data', 'categoria', 'tipo', 'status', 'frequencia'];

/**
 * GET: Retorna todas as transações da planilha
 */
function doGet() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName(SHEET_NAME) || ss.insertSheet(SHEET_NAME);
  const data = sheet.getDataRange().getValues();

  if (data.length <= 1) {
    return createResponse([]);
  }

  const headers = data[0];
  const rows = data.slice(1);

  const result = rows.map(row => {
    let obj = {};
    headers.forEach((header, i) => {
      // Formata a data se for um objeto Date do Google
      if (header === 'data' && row[i] instanceof Date) {
        obj[header] = row[i].toISOString().split('T')[0];
      } else {
        obj[header] = row[i];
      }
    });
    return obj;
  });

  return createResponse(result);
}

/**
 * POST: Salva, edita ou deleta dados
 */
function doPost(e) {
  try {
    const request = JSON.parse(e.postData.contents);
    const action = request.action;
    const payload = request.payload;

    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const sheet = ss.getSheetByName(SHEET_NAME) || ss.insertSheet(SHEET_NAME);

    if (action === 'save') {
      saveTransaction(sheet, payload);
    } else if (action === 'delete') {
      deleteTransaction(sheet, payload.id);
    } else if (action === 'syncAll') {
      syncAll(sheet, payload);
    }

    return createResponse({ status: 'success' });
  } catch (error) {
    return createResponse({ status: 'error', message: error.toString() });
  }
}

/**
 * Lógica para Salvar ou Atualizar
 */
function saveTransaction(sheet, t) {
  const data = sheet.getDataRange().getValues();
  const idToFind = t.id;
  let rowIndex = -1;

  // Procura se o ID já existe
  for (let i = 1; i < data.length; i++) {
    if (data[i][0] == idToFind) {
      rowIndex = i + 1;
      break;
    }
  }

  const rowValues = [t.id, t.descricao, t.valor, t.data, t.categoria, t.tipo, t.status, t.frequencia];

  if (rowIndex !== -1) {
    // Atualiza linha existente
    sheet.getRange(rowIndex, 1, 1, 8).setValues([rowValues]);
  } else {
    // Adiciona nova linha
    sheet.appendRow(rowValues);
  }
}

/**
 * Lógica para Deletar
 */
function deleteTransaction(sheet, id) {
  const data = sheet.getDataRange().getValues();
  for (let i = 1; i < data.length; i++) {
    if (data[i][0] == id) {
      sheet.deleteRow(i + 1);
      break;
    }
  }
}

/**
 * Lógica para Sincronizar Tudo (Sobrescreve a planilha)
 */
function syncAll(sheet, transactions) {
  sheet.clear();
  sheet.appendRow(HEADERS);
  if (transactions && transactions.length > 0) {
    const rows = transactions.map(t => [
      t.id, t.descricao, t.valor, t.data, t.categoria, t.tipo, t.status, t.frequencia
    ]);
    sheet.getRange(2, 1, rows.length, 8).setValues(rows);
  }
}

/**
 * Helper para criar a resposta JSON
 */
function createResponse(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}
