import { Transaction } from "../types";

/**
 * URL da planilha do Google Sheets utilizada como banco de dados.
 * Atualizada conforme solicitação do usuário.
 */
const API_URL = "https://script.google.com/macros/s/AKfycbyRZwkY1-CG8MDNCF-2QbMYGVK9pcI-MgcvG4HsICO46FGY4n255Gzjr5YMiU_bKlNjow/exec";

export const sheetsService = {
  /**
   * Busca todos os dados da planilha.
   * Se houver erro ou a planilha estiver vazia, retorna os dados locais se existirem.
   */
  async getAll(): Promise<Transaction[]> {
    if (!API_URL) return [];
    try {
      const response = await fetch(API_URL, {
        method: "GET",
        redirect: "follow",
        cache: "no-store"
      });

      if (!response.ok) {
        throw new Error(`Erro na rede: ${response.status}`);
      }

      const data = await response.json();

      if (!Array.isArray(data)) {
        return [];
      }

      return data.map((t: any) => ({
        ...t,
        id: t.id ? t.id.toString() : Math.random().toString(36).substr(2, 9),
        valor: typeof t.valor === 'string' ? parseFloat(t.valor.replace(',', '.')) : (parseFloat(t.valor) || 0),
        data: t.data ? t.data.toString().split('T')[0] : new Date().toISOString().split('T')[0],
        tipo: t.tipo || 'Despesa',
        status: t.status || 'Pendente',
        categoria: t.categoria || 'Outro',
        frequencia: t.frequencia || 'Esporádico'
      }));
    } catch (error) {
      console.error("Erro ao buscar dados do Google Sheets:", error);
      throw error;
    }
  },

  /**
   * Envia uma única transação para ser salva/atualizada.
   */
  async save(transaction: Transaction): Promise<boolean> {
    if (!API_URL) return false;
    try {
      // O modo 'no-cors' é necessário para evitar erros de pré-voo (preflight) com o Google Apps Script,
      // mas ele não permite ver a resposta. Assumimos sucesso se o fetch não lançar erro.
      await fetch(API_URL, {
        method: "POST",
        mode: "no-cors",
        headers: { "Content-Type": "text/plain" },
        body: JSON.stringify({ action: "save", payload: transaction })
      });
      return true;
    } catch (error) {
      console.error("Erro ao salvar no Sheets:", error);
      return false;
    }
  },

  /**
   * Remove uma transação pelo ID.
   */
  async delete(id: string): Promise<boolean> {
    if (!API_URL) return false;
    try {
      await fetch(API_URL, {
        method: "POST",
        mode: "no-cors",
        headers: { "Content-Type": "text/plain" },
        body: JSON.stringify({ action: "delete", payload: { id } })
      });
      return true;
    } catch (error) {
      console.error("Erro ao deletar no Sheets:", error);
      return false;
    }
  },

  /**
   * Sincroniza toda a lista local com a planilha (sobrescreve o que houver lá).
   */
  async syncAll(transactions: Transaction[]): Promise<boolean> {
    if (!API_URL) return false;
    try {
      await fetch(API_URL, {
        method: "POST",
        mode: "no-cors",
        headers: { "Content-Type": "text/plain" },
        body: JSON.stringify({ action: "syncAll", payload: transactions })
      });
      return true;
    } catch (error) {
      console.error("Erro ao sincronizar tudo no Sheets:", error);
      return false;
    }
  }
};

