import { Transaction } from "../types";

const API_URL = "https://script.google.com/macros/s/AKfycbyRZwkY1-CG8MDNCF-2QbMYGVK9pcI-MgcvG4HsICO46FGY4n255Gzjr5YMiU_bKlNjow/exec";

/**
 * Normaliza as chaves de um objeto para minúsculas e remove acentos comuns.
 */
const normalizeKeys = (obj: any) => {
  const normalized: any = {};
  for (const key in obj) {
    const normalizedKey = key
      .toLowerCase()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "") // Remove acentos
      .trim();
    normalized[normalizedKey] = obj[key];
  }
  return normalized;
};

export const sheetsService = {
  async getAll(): Promise<Transaction[]> {
    if (!API_URL) return [];
    try {
      const response = await fetch(API_URL, {
        method: "GET",
        redirect: "follow",
        cache: "no-store"
      });

      if (!response.ok) throw new Error(`Erro na rede: ${response.status}`);

      const data = await response.json();
      if (!Array.isArray(data)) return [];

      return data.map((item: any) => {
        const t = normalizeKeys(item);

        // Parsing de valor com suporte a múltiplos nomes de colunas e formatos
        const rawValue = t.valor !== undefined ? t.valor : (t.value !== undefined ? t.value : t.montante);
        let valorNumerico = 0;
        if (typeof rawValue === 'number') {
          valorNumerico = rawValue;
        } else if (typeof rawValue === 'string') {
          // Remove símbolos de moeda e ajusta separador decimal
          const cleaned = rawValue.replace(/[R$\s]/g, '').replace('.', '').replace(',', '.');
          valorNumerico = parseFloat(cleaned) || 0;
        }

        // Mapeamento flexível de status
        let rawStatus = (t.status || t.situacao || t.estado || 'Pendente').toString().trim();
        // Normaliza primeira letra maiúscula
        rawStatus = rawStatus.charAt(0).toUpperCase() + rawStatus.slice(1).toLowerCase();
        const finalStatus = (rawStatus === 'Pago' || rawStatus === 'Pendente') ? rawStatus : 'Pendente';

        // Mapeamento de data
        let finalDate = t.data || t.date || new Date().toISOString().split('T')[0];
        if (typeof finalDate === 'string' && finalDate.includes('T')) {
          finalDate = finalDate.split('T')[0];
        }

        return {
          id: t.id ? t.id.toString() : Math.random().toString(36).substr(2, 9),
          descricao: t.descricao || t.description || t.nome || "Sem descrição",
          valor: valorNumerico,
          data: finalDate,
          tipo: t.tipo || t.type || 'Despesa',
          status: finalStatus as any,
          categoria: t.categoria || t.category || 'Outro',
          frequencia: t.frequencia || t.frequency || 'Esporádico'
        } as Transaction;
      });
    } catch (error) {
      console.error("Erro ao buscar dados do Google Sheets:", error);
      throw error;
    }
  },

  async save(transaction: Transaction): Promise<boolean> {
    if (!API_URL) return false;
    try {
      await fetch(API_URL, {
        method: "POST",
        mode: "no-cors",
        headers: { "Content-Type": "text/plain" },
        body: JSON.stringify({ action: "save", payload: transaction })
      });
      return true;
    } catch (error) {
      console.error("Erro ao salvar no Sheets:", error);
      return false;
    }
  },

  async delete(id: string): Promise<boolean> {
    if (!API_URL) return false;
    try {
      await fetch(API_URL, {
        method: "POST",
        mode: "no-cors",
        headers: { "Content-Type": "text/plain" },
        body: JSON.stringify({ action: "delete", payload: { id } })
      });
      return true;
    } catch (error) {
      console.error("Erro ao deletar no Sheets:", error);
      return false;
    }
  },

  async syncAll(transactions: Transaction[]): Promise<boolean> {
    if (!API_URL) return false;
    try {
      await fetch(API_URL, {
        method: "POST",
        mode: "no-cors",
        headers: { "Content-Type": "text/plain" },
        body: JSON.stringify({ action: "syncAll", payload: transactions })
      });
      return true;
    } catch (error) {
      console.error("Erro ao sincronizar tudo no Sheets:", error);
      return false;
    }
  }
};

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Transaction } from './types.ts';
import Dashboard from './components/Dashboard.tsx';
import TransactionList from './components/TransactionList.tsx';
import InvestmentList from './components/InvestmentList.tsx';
import { sheetsService } from './services/googleSheetsService.ts';

const App: React.FC = () => {
  const [isHome, setIsHome] = useState(true);
  const [hideValues, setHideValues] = useState(true);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'transactions' | 'investments'>('dashboard');
  const [isLoading, setIsLoading] = useState(true);
  const [syncStatus, setSyncStatus] = useState<'online' | 'offline' | 'syncing'>('syncing');

  const [selectedMonth, setSelectedMonth] = useState(new Date().getMonth());
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());

  const hasLoadedInitialData = useRef(false);

  // Carrega transações do LocalStorage apenas como fallback imediato
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('ff_transactions');
    return saved ? JSON.parse(saved) : [];
  });

  // Salva no localStorage sempre que as transações mudarem
  useEffect(() => {
    localStorage.setItem('ff_transactions', JSON.stringify(transactions));
  }, [transactions]);

  /**
   * Função de carregamento de dados da Nuvem.
   * Chamada automaticamente na inicialização.
   */
  const loadData = useCallback(async () => {
    setSyncStatus('syncing');
    try {
      const remoteData = await sheetsService.getAll();

      if (Array.isArray(remoteData)) {
        if (remoteData.length > 0) {
          // Se houver dados na nuvem, eles são a fonte da verdade
          setTransactions(remoteData);
        } else {
          // Se a planilha estiver vazia, verificamos se o app local tem algo para subir
          setTransactions(current => {
            if (current.length > 0) {
              console.log("Planilha vazia. Enviando dados locais para nuvem...");
              sheetsService.syncAll(current);
            }
            return current;
          });
        }
        setSyncStatus('online');
      } else {
        setSyncStatus('offline');
      }
    } catch (error) {
      console.error("Erro na sincronização inicial:", error);
      setSyncStatus('offline');
      // Não limpa 'transactions' para manter o que está no cache local em caso de erro
    } finally {
      setIsLoading(false);
      hasLoadedInitialData.current = true;
    }
  }, []);

  // Inicialização
  useEffect(() => {
    if (!hasLoadedInitialData.current) {
      loadData();
    }
  }, [loadData]);

  const monthNames = ["Janeiro", "Fevereiro", "Março", "Abril", "Maio", "Junho", "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"];

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      if (!t.data) return false;
      const datePart = t.data.toString().split('T')[0];
      const [year, month] = datePart.split('-').map(Number);
      return (month - 1) === selectedMonth && year === selectedYear;
    });
  }, [transactions, selectedMonth, selectedYear]);

  const addTransaction = async (t: Omit<Transaction, 'id'>) => {
    const newTransaction = { ...t, id: Math.random().toString(36).substr(2, 9) } as Transaction;
    setTransactions(prev => [newTransaction, ...prev]);
    setSyncStatus('syncing');
    const success = await sheetsService.save(newTransaction);
    setSyncStatus(success ? 'online' : 'offline');
  };

  const updateTransaction = async (updated: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updated.id ? updated : t));
    setSyncStatus('syncing');
    const success = await sheetsService.save(updated);
    setSyncStatus(success ? 'online' : 'offline');
  };

  const deleteTransaction = async (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
    setSyncStatus('syncing');
    const success = await sheetsService.delete(id);
    setSyncStatus(success ? 'online' : 'offline');
  };

  if (isHome) {
    return (
      <div className="min-h-screen bg-white flex flex-col items-center justify-center p-6 text-center animate-enter overflow-hidden">
        <div className="w-20 h-20 bg-brand-500 rounded-[2rem] flex items-center justify-center mb-8 shadow-2xl shadow-brand-200">
          <svg className="w-10 h-10 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
        </div>
        <h1 className="text-4xl font-black text-slate-800 mb-2 tracking-tight">Finance<span className="text-brand-500">Peres</span></h1>
        <p className="text-slate-400 max-w-sm mb-12 font-medium">Controle financeiro inteligente integrado ao Google Sheets.</p>
        <button onClick={() => setIsHome(false)} className="w-full max-w-xs py-5 bg-brand-500 text-white rounded-2xl font-black text-lg shadow-xl hover:bg-brand-600 transition-all active:scale-95">Acessar Sistema</button>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-[#f8fafc] overflow-hidden">
      {isLoading && !hasLoadedInitialData.current && (
        <div className="fixed inset-0 bg-white/80 backdrop-blur-sm z-[200] flex flex-col items-center justify-center">
